    if (!cell || !table) return;
    const row = cell.parentNode as HTMLTableRowElement;
    if (row) {
      table.classList.add('is-resizing');
      const newRow = row.parentNode!.insertBefore(row.cloneNode(true), where === 'above' ? row : row.nextSibling);
