import React, { useRef, useEffect, useState, useMemo, Suspense } from 'react';
import { RibbonTab } from '../types';
import { RibbonTabBar } from './ribbon/RibbonTabBar';
import { LoadingSpinner } from '@/components/LoadingSpinner';

// Helper for safe lazy loading
const safeLazy = (importPromise: Promise<Record<string, React.ComponentType<any>>>, name: string) => 
    React.lazy(() => importPromise.then(m => ({ default: m[name] || (() => <div className="p-2 text-xs text-red-500">Failed to load {name}</div>) })));

// Lazy Load Tabs
const HomeTab = safeLazy(import('./ribbon/tabs/HomeTab/HomeTab'), 'HomeTab');
const InsertTab = safeLazy(import('./ribbon/tabs/InsertTab/InsertTab'), 'InsertTab');
const ViewTab = safeLazy(import('./ribbon/tabs/ViewTab/ViewTab'), 'ViewTab');
const FileTab = safeLazy(import('./ribbon/tabs/FileTab/FileTab'), 'FileTab');
const LayoutTab = safeLazy(import('./ribbon/tabs/LayoutTab/LayoutTab'), 'LayoutTab');
const ReferencesTab = safeLazy(import('./ribbon/tabs/ReferencesTab/ReferencesTab'), 'ReferencesTab');
const MailingsTab = safeLazy(import('./ribbon/tabs/MailingsTab/MailingsTab'), 'MailingsTab');
const AIAssistantTab = safeLazy(import('./ribbon/tabs/AIAssistantTab/AIAssistantTab'), 'AIAssistantTab');
const DrawTab = safeLazy(import('./ribbon/tabs/DrawTab/DrawTab'), 'DrawTab');
const DesignTab = safeLazy(import('./ribbon/tabs/DesignTab/DesignTab'), 'DesignTab');
const ReviewTab = safeLazy(import('./ribbon/tabs/ReviewTab/ReviewTab'), 'ReviewTab');
const TableDesignTab = safeLazy(import('./ribbon/tabs/InsertTab/tables/tabledesign_subTab/tabledesign'), 'TableDesignTab');
const TableLayoutTab = safeLazy(import('./ribbon/tabs/InsertTab/tables/tablelayout_subTab/tablelayout'), 'TableLayoutTab');
const EquationTab = safeLazy(import('./ribbon/tabs/InsertTab/symbols/equation_subTab/EquationTab'), 'EquationTab');
const HeaderFooterTab = safeLazy(import('./ribbon/tabs/HeaderFooterTab/HeaderFooterTab'), 'HeaderFooterTab');

interface RibbonProps {
  activeTab: RibbonTab | null;
  onTabChange: (tab: RibbonTab) => void;
}

const TabLoading = () => (
  <div className="flex items-center justify-center h-20 w-full text-slate-400 gap-3">
    <LoadingSpinner className="w-5 h-5" />
    <span className="text-xs">Loading tools...</span>
  </div>
);

const Ribbon: React.FC<RibbonProps> = ({ 
  activeTab, 
  onTabChange 
}) => {
  const [height, setHeight] = useState<number>(0);
  const contentRef = useRef<HTMLDivElement>(null);
  const scrollContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
     if (activeTab && contentRef.current) {
        const timer = setTimeout(() => {
            if (contentRef.current) {
                const contentHeight = contentRef.current.scrollHeight;
                setHeight(Math.max(contentHeight, 100));
            }
        }, 50);
        return () => clearTimeout(timer);
     } else {
        setTimeout(() => setHeight(0), 0);
     }
  }, [activeTab]);

  useEffect(() => {
    const el = scrollContainerRef.current;
    if (el) {
      const onWheel = (e: WheelEvent) => {
        if (e.deltaY === 0) return;
        if (el.scrollWidth > el.clientWidth) {
           e.preventDefault();
           el.scrollLeft += e.deltaY;
        }
      };
      el.addEventListener('wheel', onWheel, { passive: false });
      return () => el.removeEventListener('wheel', onWheel);
    }
  }, [activeTab]); 

  const tabContent = useMemo(() => {
    return (
      <Suspense fallback={<TabLoading />}>
        {(() => {
          switch (activeTab) {
            case RibbonTab.HOME: return <HomeTab />;
            case RibbonTab.INSERT: return <InsertTab />;
            case RibbonTab.DRAW: return <DrawTab />;
            case RibbonTab.DESIGN: return <DesignTab />;
            case RibbonTab.LAYOUT: return <LayoutTab />;
            case RibbonTab.REFERENCES: return <ReferencesTab />;
            case RibbonTab.MAILINGS: return <MailingsTab />;
            case RibbonTab.REVIEW: return <ReviewTab />;
            case RibbonTab.VIEW: return <ViewTab />;
            case RibbonTab.FILE: return <FileTab />;
            case RibbonTab.AI_ASSISTANT: return <AIAssistantTab />;
            case RibbonTab.TABLE_DESIGN: return <TableDesignTab />;
            case RibbonTab.TABLE_LAYOUT: return <TableLayoutTab />;
            case RibbonTab.EQUATION: return <EquationTab />;
            case RibbonTab.HEADER_FOOTER: return <HeaderFooterTab />;
            default: return activeTab ? <div className="flex items-center justify-center w-full h-full text-slate-400 italic text-xs">Tools coming soon...</div> : null;
          }
        })()}
      </Suspense>
    );
  }, [activeTab]);

  const handleMouseDown = (e: React.MouseEvent) => {
    const target = e.target as HTMLElement;
    if (['INPUT', 'TEXTAREA', 'SELECT'].includes(target.tagName) || target.isContentEditable) {
      return;
    }
    e.preventDefault();
  };

  return (
    <div 
      onMouseDown={handleMouseDown}
      className="flex flex-col z-20 no-print relative shadow-sm bg-slate-50 dark:bg-[#0f172a] transition-colors duration-300"
    >
      <RibbonTabBar activeTab={activeTab} onTabChange={onTabChange} />

      <div 
        className={`bg-white dark:bg-[#1e293b] border-b border-slate-200 dark:border-slate-700 relative z-10 transition-all duration-300 ease-[cubic-bezier(0.4,0,0.2,1)] overflow-hidden ${activeTab ? 'opacity-100' : 'opacity-0'}`}
        style={{ 
          height: activeTab ? `${Math.max(height, 100)}px` : '0px'
        }}
      >
         <div 
            ref={scrollContainerRef}
            className="h-full w-full overflow-x-auto overflow-y-hidden no-scrollbar touch-pan-x"
         >
            <div 
                ref={contentRef}
                className="flex h-full min-w-max items-center px-1 md:px-3 py-1 animate-in slide-in-from-top-2 duration-300 fill-mode-forwards"
            >
                {activeTab && tabContent}
            </div>
         </div>

         <div className="absolute right-0 top-0 bottom-0 w-8 bg-gradient-to-l from-white dark:from-[#1e293b] to-transparent pointer-events-none md:hidden"></div>
      </div>
    </div>
  );
};

export default React.memo(Ribbon);

import React, { useMemo } from 'react';
import { PageConfig } from '../types';
import { PAGE_SIZES, PAGE_MARGIN_PADDING } from '../constants';

interface RulerProps {
  pageConfig: PageConfig;
  zoom: number;
  onDoubleClick?: () => void;
}

export const Ruler: React.FC<RulerProps> = React.memo(({ pageConfig, zoom, onDoubleClick }) => {

  // Width in px (96 DPI)
  const width = useMemo(() => {
      if (pageConfig.size === 'Custom' && pageConfig.customWidth) {
          return pageConfig.customWidth * 96;
      }
      const base = PAGE_SIZES[pageConfig.size as string] || PAGE_SIZES['Letter'];
      return pageConfig.orientation === 'portrait' ? base.width : base.height;
  }, [pageConfig.size, pageConfig.orientation, pageConfig.customWidth]);

  const scale = zoom / 100;

  // Calculate margins in pixels based on explicit config
  const margins = useMemo(() => {
    const m = pageConfig.margins;
    let left = m.left * 96;
    const right = m.right * 96;

    // Add gutter to left for simplified global ruler view
    left += m.gutter * 96;

    return { left, right };
  }, [pageConfig.margins]);

  // Generate ticks
  // 1 inch = 96px
  const ticks = useMemo(() => {
    const totalInches = Math.ceil(width / 96);
    return Array.from({ length: totalInches * 8 + 1 }).map((_, i) => {
      const pos = i * (96 / 8); // 1/8th inch increments
      if (pos > width) return null;

      const isInch = i % 8 === 0;
      const isHalf = i % 4 === 0;
      const isQuarter = i % 2 === 0;

      let height = 'h-1';
      if (isInch) height = 'h-2.5';
      else if (isHalf) height = 'h-1.5';
      else if (isQuarter) height = 'h-1';

      return (
        <div 
          key={i} 
          className={`absolute top-0 border-l border-slate-500 ${height}`} 
          style={{ left: `${pos}px` }}
        >
          {isInch && i > 0 && (
            <span className="absolute top-2.5 -left-1 text-[8px] font-semibold text-slate-600 select-none">
              {i / 8}
            </span>
          )}
        </div>
      );
    });
  }, [width]);

  // Fix layout footprint
  const marginRight = -(width * (1 - scale));

  return (
    <div 
      onDoubleClick={onDoubleClick}
      className="h-6 bg-[#D1D5DB] border-b border-slate-300 flex items-end relative select-none no-print z-10 shadow-sm origin-top-left cursor-default transition-all duration-300 ease-in-out"
      title="Double-click to open Page Setup"
      style={{ 
        width: `${width}px`,
        transform: `scale(${scale})`,
        marginRight: `${marginRight}px`,
        marginBottom: '0px' 
      }}
    >
      {/* White writable area representation */}
      <div 
        className="absolute top-0 bottom-0 bg-white border-x border-slate-300 h-full z-0 pointer-events-none"
        style={{
          left: `${margins.left}px`,
          right: `${margins.right}px`
        }}
      ></div>

      {/* Ticks Container */}
      <div className="w-full h-full bg-transparent relative overflow-hidden z-10 pointer-events-none">
        {ticks}

        {/* Left Indent Markers - made interactive later, currently visual only but receive double click */}
        <div 
          className="absolute top-0 h-full w-3 cursor-ew-resize group z-20 hover:brightness-110 transition-all pointer-events-auto"
          style={{ left: `${margins.left - 6}px` }}
          onDoubleClick={(e) => { e.stopPropagation(); onDoubleClick?.(); }}
        >
            {/* Hanging Indent (Top Triangle) */}
            <div className="w-0 h-0 border-l-[5px] border-l-transparent border-r-[5px] border-r-transparent border-t-[6px] border-t-[#4b5563] absolute top-0 left-0 drop-shadow-sm" title="First Line Indent"></div>
            {/* Left Indent (Bottom Triangle) */}
            <div className="w-0 h-0 border-l-[5px] border-l-transparent border-r-[5px] border-r-transparent border-b-[6px] border-b-[#4b5563] absolute top-[8px] left-0 drop-shadow-sm" title="Hanging Indent"></div>
            {/* Left Indent (Square) */}
            <div className="w-[10px] h-[5px] bg-[#4b5563] absolute top-[14px] left-0 drop-shadow-sm" title="Left Indent"></div>
        </div>

        {/* Right Indent Marker */}
        <div 
           className="absolute top-0 h-full w-3 cursor-ew-resize group z-20 hover:brightness-110 transition-all pointer-events-auto"
           style={{ left: `${width - margins.right - 5}px` }}
           onDoubleClick={(e) => { e.stopPropagation(); onDoubleClick?.(); }}
        >
             <div className="w-0 h-0 border-l-[5px] border-l-transparent border-r-[5px] border-r-transparent border-b-[8px] border-b-[#4b5563] absolute top-[11px] left-0 drop-shadow-sm" title="Right Indent"></div>
        </div>
      </div>
    </div>
  );
});

import React, { useRef, useEffect, useState, memo, useCallback } from 'react';
import { RibbonTab } from '../../types';
