       const loadAll = async () => {
           const pending = CATEGORY_NAMES.filter(name => !loadedData[name] && !loadingStates[name]);
           if (pending.length === 0) return;

           setLoadingStates(prev => {
               const next = {...prev};
               pending.forEach(name => next[name] = true);
               return next;
           });

           const results = await Promise.allSettled(pending.map(name => 
               CATEGORY_LOADERS[name]().then(data => ({ name, data }))
           ));

           const newLoadedData = {...loadedData};
           const newLoadingStates = {...loadingStates};

           results.forEach(res => {
               if (res.status === 'fulfilled') {
                   newLoadedData[res.value.name] = res.value.data;
                   newLoadingStates[res.value.name] = false;
               }
           });

           // Clean up loading states
           pending.forEach(name => newLoadingStates[name] = false);

           setLoadedData(newLoadedData);
           setLoadingStates(newLoadingStates);
       };

       loadAll();
    }
  }, [deferredSearchTerm, loadedData, loadingStates]);

  // Reset AI results when user types new search term to force DB search or re-generation
  useEffect(() => {
      setAiResults([]);
  }, [deferredSearchTerm]);

  // --- AI Generation Logic ---
  const handleGenerateTemplates = async () => {
    if (!deferredSearchTerm.trim()) return;

    setIsSearchingAI(true);
    setAiResults([]); // Clear current view

    try {
        const min = 20;
        const max = 100;
        const count = Math.floor(Math.random() * (max - min + 1)) + min;

        const prompt = `Generate exactly ${count} unique predictive document templates related to the topic: "${deferredSearchTerm}".`;

        // Use generate_template_list to get simple JSON array, bypassing complex doc structure schema
        const response = await generateAIContent('generate_template_list' as AIOperation, '', prompt, 'gemini-3-pro-preview');

        let clean = response.replace(/```(?:json)?\s*/g, '').replace(/```/g, '').trim();

        // Fix trailing commas or unquoted keys using robust parsing logic
        try {
           // Robust JSON cleanup
           clean = clean.replace(/\/\/.*$/gm, ''); // Remove comments
           clean = clean.replace(/,\s*([}\]])/g, '$1'); // Trailing commas
           clean = clean.replace(/([{,])\s*([a-zA-Z0-9_]+)\s*:/g, '$1"$2":'); // Unquoted keys

           const start = clean.indexOf('[');
           const end = clean.lastIndexOf(']');
           if (start !== -1 && end !== -1) {
               clean = clean.substring(start, end + 1);
           }

           const parsed = JSON.parse(clean);
           if (Array.isArray(parsed)) {
               setAiResults(parsed.map(x => ({...x, category: 'AI Generated'})));
           }
        } catch (e) {
             console.warn("AI JSON Parse Error", e);
        }
    } catch (err) {
        console.error("AI Generation failed", err);
    } finally {
        setIsSearchingAI(false);
    }
  };

  // --- Expansion Handling (Lazy Load on Click) ---
  const handleToggleCategory = async (category: string) => {
      if (expandedCategory === category) {
          setExpandedCategory(null);
          return;
      }

      setExpandedCategory(category);

      if (!loadedData[category] && !loadingStates[category]) {
          setLoadingStates(prev => ({...prev, [category]: true}));
          try {
              const data = await CATEGORY_LOADERS[category]();
              setLoadedData(prev => ({...prev, [category]: data}));
          } catch (error) {
              console.error(`Failed to load category: ${category}`, error);
          } finally {
              setLoadingStates(prev => ({...prev, [category]: false}));
          }
      }
  };

  // --- Filtering Logic ---
  const filteredItems = useMemo(() => {
    if (!deferredSearchTerm) return null;

    // Priority 1: AI Results (if user clicked generate)
    if (aiResults.length > 0) {
        return aiResults;
    }

    // Priority 2: Local DB Search
    const lowerSearch = deferredSearchTerm.toLowerCase();
    const results: { l: string, f: string, category: string }[] = [];

    Object.entries(loadedData).forEach(([category, items]) => {
      if (items && Array.isArray(items)) {
          items.forEach(item => {
             // Standard Search: Check label only
             if (item.l.toLowerCase().includes(lowerSearch)) {
                 results.push({ ...item, category });
             }
          });
      }
    });
    return results.slice(0, 100); // Limit results for performance
  }, [deferredSearchTerm, loadedData, aiResults]);

  // Calculate total items from hardcoded counts
  const totalCount = Object.values(CATEGORY_COUNTS).reduce((acc, curr) => acc + curr, 0);

  return (
     <div className="flex flex-col flex-1 min-h-0 bg-slate-50/50">
         <div className="px-3 pt-3 pb-2 border-t border-slate-100 bg-slate-50 sticky top-0 z-10">
             <div className="flex items-center justify-between mb-2">
                 <div className="flex items-center gap-2">
                     <div className="text-[10px] font-bold text-slate-500 uppercase tracking-wider flex items-center gap-1.5">
                         {selectedTone ? (
                            <>
                                <Zap size={10} className="text-amber-500 fill-amber-500"/> {selectedTone} Gallery
                            </>
                         ) : (
                            <>
                                <LayoutTemplate size={10}/> Template Collection
                            </>
                         )}
                     </div>
                     {/* AI Search Button */}
                     <button 
                        onClick={() => {
                            setIsAIMode(!isAIMode);
                            if (!isAIMode) {
                                // Focus input when enabling AI mode
                                const input = document.querySelector('input[type="text"]') as HTMLInputElement;
                                if(input) input.focus();
                            }
                        }}
                        className={`flex items-center gap-1 px-1.5 py-0.5 rounded text-[9px] font-bold uppercase tracking-wide transition-all ${
                            isAIMode 
                            ? 'bg-indigo-100 text-indigo-700 shadow-sm ring-1 ring-indigo-200' 
                            : 'text-slate-400 hover:text-indigo-600 hover:bg-indigo-50'
                        }`}
                     >
                        <Sparkles size={8} className={isAIMode ? "fill-indigo-300" : ""} /> AI Search
                     </button>
                 </div>
                 <span className="text-[9px] bg-slate-200 text-slate-600 px-1.5 py-0.5 rounded-full font-mono">
                    {totalCount}
                 </span>
             </div>
             <div className="relative group">
                 {isAIMode ? (
                    <div className="absolute left-2.5 top-1/2 -translate-y-1/2">
                        <Sparkles size={12} className="text-indigo-500 animate-pulse" />
                    </div>
                 ) : (
                    <Search size={12} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-500"/>
                 )}

                 <input 
                    type="text" 
                    placeholder={isAIMode ? "Describe what to find (e.g. 'Space Treaty')..." : "Search document type..."} 
                    className={`w-full pl-7 ${isAIMode && deferredSearchTerm ? 'pr-14' : 'pr-2'} py-1.5 text-xs border rounded-md outline-none transition-all ${
                        isAIMode 
                        ? 'bg-indigo-50/30 border-indigo-200 focus:border-indigo-500 focus:ring-2 focus:ring-indigo-100 placeholder:text-indigo-400/70 text-indigo-900'
                        : 'bg-white border-slate-200 focus:border-blue-500 focus:ring-2 focus:ring-blue-100'
                    }`}
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && isAIMode && handleGenerateTemplates()}
                 />

                 {/* Manual Generate Button for AI Mode */}
                 {isAIMode && deferredSearchTerm && (
                     <div className="absolute right-1 top-1/2 -translate-y-1/2 flex items-center">
                         {isSearchingAI ? (
                             <div className="px-2">
                                <LoadingSpinner className="w-3.5 h-3.5" />
                             </div>
                         ) : (
                             <button
                                onClick={handleGenerateTemplates}
                                className="flex items-center justify-center bg-indigo-600 hover:bg-indigo-700 text-white rounded-md p-1 transition-all shadow-sm active:scale-95"
                                title="Generate Templates"
                             >
                                <Wand2 size={10} className="fill-white/20"/>
                             </button>
                         )}
                     </div>
                 )}
             </div>
         </div>

         <div className="overflow-y-auto scrollbar-thin scrollbar-thumb-slate-200 hover:scrollbar-thumb-slate-300 flex-1 px-2 pb-2">
             {deferredSearchTerm ? (
                 <div className="space-y-0.5 animate-in fade-in slide-in-from-top-2 duration-200">
                     {filteredItems && filteredItems.length > 0 ? (
                         filteredItems.map((item, idx) => {
                             const Icon = getIconForOption(item.l);
                             const isAIItem = item.category === 'AI Generated';
                             return (
                                 <button 
                                    key={idx} 
                                    onClick={() => onSelect(item)}
                                    className={`w-full text-left px-3 py-2 hover:shadow-sm border border-transparent rounded-md group transition-all ${isAIItem ? 'hover:bg-indigo-50/50 hover:border-indigo-100' : 'hover:bg-white hover:border-slate-100'}`}
                                 >
                                     <div className="flex justify-between items-baseline min-w-0">
                                         <span className={`text-xs font-semibold flex items-center gap-2 truncate ${isAIItem ? 'text-indigo-700' : 'text-slate-700 group-hover:text-blue-700'}`}>
