                                             <span className="truncate">{item.l}</span>
                                         </span>
                                         <span className={`text-[9px] font-medium uppercase tracking-tight shrink-0 ml-2 ${isAIItem ? 'text-indigo-400 bg-indigo-50 px-1 rounded' : 'text-slate-400'}`}>
