interface AdvancedGrammarDialogProps {
  isOpen: boolean;
  onClose: () => void;
  initialText: string;
  onApply: (text: string) => void;
}

type AnalysisResult = {
  correctedText: string;
  readabilityScore: number;
  readabilityLevel: string;
  passiveVoiceCount: number;
  improvements: string[];
};

interface HistoryItem {
  id: string;
  originalText: string;
