                        >
                            <ArrowLeft size={20} />
                        </button>

                        <div className="p-1.5 bg-gradient-to-br from-indigo-600 to-violet-600 rounded-lg shadow-md shadow-indigo-200/50 dark:shadow-none">
                            <Wand2 className="text-white" size={16} />
                        </div>
                        Editor Pro
