                                        onChange={(e) => setCustomPages(e.target.value)}
                                        placeholder="e.g. 1-5, 8, 11-13"
                                        className="w-full px-4 py-3 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-sm font-medium text-slate-700 dark:text-slate-200 focus:outline-none focus:border-blue-500 focus:ring-2 focus:ring-blue-500/10 transition-all placeholder:text-slate-400"
                                    />
                                </div>
                            )}
                        </div>

                        <div className="w-full h-px bg-slate-100 dark:bg-slate-800"></div>

                        {/* Page Settings section - PDF only */}
                        <div className="space-y-4">
                            <div className="flex justify-between items-center">
                                <h3 className="text-xs font-bold text-slate-400 uppercase tracking-wider">Page Settings</h3>
                                <span className="text-[10px] text-slate-400 font-mono flex items-center gap-1">
                                    <Ruler size={10} /> {getDimensionsDisplay()}
                                </span>
                            </div>

                            <PrintSelect
                                label="Orientation"
                                value={localConfig.orientation}
                                onChange={(v: any) => handleSettingChange('orientation', v)}
                                options={[
                                    { value: 'portrait', label: 'Portrait Orientation' },
                                    { value: 'landscape', label: 'Landscape Orientation' }
                                ]}
                                icon={FileType}
                            />

                            <PrintSelect
                                label="Paper Size"
                                value={localConfig.size}
                                onChange={(v: any) => handleSettingChange('size', v)}
                                options={PAPER_FORMATS.map(f => ({ 
                                    value: f.id, 
                                    label: `${f.label} (${f.width} x ${f.height})` 
                                }))}
                                icon={FileText}
                            />

                            <PrintSelect
                                label="Margins"
                                value={localConfig.marginPreset}
                                onChange={(v: any) => handleSettingChange('marginPreset', v)}
                                options={Object.keys(MARGIN_PRESETS).map(m => ({ 
                                    value: m, 
                                    label: formatPresetLabel(m) 
                                }))}
                                icon={LayoutTemplate}
                            />
                        </div>
                    </>
                ) : (
                    <div className="p-4 bg-blue-50/50 dark:bg-blue-950/20 border border-blue-100 dark:border-blue-900/50 rounded-xl space-y-1.5 animate-in fade-in slide-in-from-top-1 duration-200">
                        <p className="text-xs font-semibold text-blue-700 dark:text-blue-400">Flowable Format Info</p>
                        <p className="text-xs text-slate-500 dark:text-slate-400 leading-relaxed">
                            Formats like <strong>{exportType.toUpperCase()}</strong> do not have pagination, margins, or orientation parameters. They will export your document text and structure directly to your computer.
                        </p>
                    </div>
                )}

                {isMobile && <div className="h-20"></div>}
            </div>

            {!isMobile && (
                <div className="p-5 border-t border-slate-200 dark:border-slate-800 bg-slate-50 dark:bg-slate-900/50 shrink-0 flex flex-col gap-3">
                    <button 
                        onClick={onPrint}
                        disabled={isPreparing}
                        className="w-full py-3.5 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold text-base shadow-lg shadow-blue-200/50 dark:shadow-none transition-all flex items-center justify-center gap-3 disabled:opacity-70 active:scale-[0.98]"
                    >
                        {isPreparing ? (
                            <LoadingSpinner className="w-5 h-5 text-white"/>
                        ) : (
                            <Download size={20}/>
                        )}
                        <span>
                            {isPreparing ? (
                                exportType === 'pdf' ? 'Preparing PDF...' : 'Preparing Export...'
                            ) : exportType === 'pdf' ? (
                                'Print / Save as PDF'
                            ) : exportType === 'doc' ? (
                                'Export Word Document (.doc)'
                            ) : exportType === 'rtf' ? (
                                'Export Rich Text Format (.rtf)'
                            ) : exportType === 'html' ? (
                                'Export Web Page (.html)'
                            ) : exportType === 'txt' ? (
                                'Export Plain Text (.txt)'
                            ) : exportType === 'md' ? (
                                'Export Markdown (.md)'
                            ) : (
                                'Export JSON (.json)'
                            )}
                        </span>
                    </button>
                    <p className="text-[10px] text-center text-slate-400">
                        {exportType === 'pdf' ? 'Uses high-fidelity vector printing' : 'Downloads directly to your system'}
                    </p>
                </div>
            )}
        </div>
    );
};

export const PrintModal: React.FC = () => {
  const { content, pageConfig: globalConfig, headerContent, footerContent, documentTitle, setPageConfig, currentPage, viewMode, setViewMode } = useEditor();
  const { closeModal } = useFileTab();

  const [mobileTab, setMobileTab] = useState<'settings' | 'preview'>('settings');
  const [localConfig, setLocalConfig] = useState<PageConfig>({ ...globalConfig });
  const [previewPages, setPreviewPages] = useState<{ html: string, config: PageConfig }[]>([]);
  const [isPreparingPrint, setIsPreparingPrint] = useState(false);
  const [copies, setCopies] = useState(1);
  const [isMobile, setIsMobile] = useState(false);

  // Print Range State
  const [printRange, setPrintRange] = useState<'all' | 'current' | 'custom'>('all');
  const [customPages, setCustomPages] = useState('');
  const [exportType, setExportType] = useState<ExportType>('pdf');
  const [documentScope, setDocumentScope] = useState<'current' | 'all'>('current');
  const [allSavedDocsPages, setAllSavedDocsPages] = useState<any[]>([]);

  useEffect(() => {
      const checkMobile = () => setIsMobile(window.innerWidth < 768);
      checkMobile();
      window.addEventListener('resize', checkMobile);
      return () => window.removeEventListener('resize', checkMobile);
  }, []);

  useEffect(() => {
    const timer = setTimeout(() => {
        const result = paginateContent(content, localConfig);
        setPreviewPages(result.pages);
    }, 50); 
    return () => clearTimeout(timer);
  }, [content, localConfig]);

  useEffect(() => {
    if (documentScope === 'all') {
      try {
        const savedDocs = JSON.parse(localStorage.getItem('saved_documents') || '{}');
        const pages: any[] = [];

        Object.keys(savedDocs).forEach(docName => {
          const doc = savedDocs[docName];
          const docConfig = doc.documentModel?.pageConfig || localConfig;
          const result = paginateContent(doc.content || '', docConfig);

          const docHeader = doc.documentModel?.headerContent || headerContent;
          const docFooter = doc.documentModel?.footerContent || footerContent;

          result.pages.forEach((page, pageIdx) => {
            let pageHeader = docHeader || '';
            if (pageHeader.includes('[Header]')) {
              pageHeader = pageHeader.replace('[Header]', '');
            }

            let pageFooter = docFooter || '';
            pageFooter = pageFooter.replace(/\[Page \d+\]/g, `[Page ${pageIdx + 1}]`)
                                   .replace(/<span class="page-number-placeholder">.*?<\/span>/g, `${pageIdx + 1}`);

            let wIn = 8.5;
            let hIn = 11;
            if (docConfig.size === 'Custom' && docConfig.customWidth && docConfig.customHeight) {
              wIn = docConfig.customWidth;
              hIn = docConfig.customHeight;
            } else {
              const base = PAGE_SIZES[docConfig.size as string] || PAGE_SIZES['Letter'];
              wIn = docConfig.orientation === 'landscape' ? base.height / 96 : base.width / 96;
              hIn = docConfig.orientation === 'landscape' ? base.width / 96 : base.height / 96;
            }

            pages.push({
              html: page.html,
              config: docConfig,
              docTitle: docName,
              isFirstPageOfDoc: pageIdx === 0,
              headerHtml: pageHeader,
              footerHtml: pageFooter,
              widthIn: wIn,
              heightIn: hIn,
              margins: {
                top: docConfig.margins.top + (docConfig.gutterPosition === 'top' ? (docConfig.margins.gutter || 0) : 0),
                bottom: docConfig.margins.bottom,
                left: docConfig.margins.left + (docConfig.gutterPosition === 'left' ? (docConfig.margins.gutter || 0) : 0),
                right: docConfig.margins.right
              },
              headerDistance: docConfig.headerDistance || 0.5,
              footerDistance: docConfig.footerDistance || 0.5
            });
          });
        });

        setAllSavedDocsPages(pages);
      } catch (e) {
        console.error("Error paginating all saved docs:", e);
      }
    }
  }, [documentScope, localConfig, headerContent, footerContent]);

  const handleBatchExport = async () => {
    const savedDocs = JSON.parse(localStorage.getItem('saved_documents') || '{}');
    const docNames = Object.keys(savedDocs);
    if (docNames.length === 0) {
      alert("No saved documents found to export.");
      return;
    }

    setIsPreparingPrint(true);
    try {
      for (let i = 0; i < docNames.length; i++) {
        const name = docNames[i];
        const doc = savedDocs[name];
        const currentContent = doc.content || '';
        const currentTitle = name;
        const currentConfig = doc.documentModel?.pageConfig || localConfig;

        let data = currentContent;
        let mime = 'text/html';
        let fileExt = 'html';

        if (exportType === 'html') {
          data = `<!DOCTYPE html><html><head>    <meta charset="utf-8">    <title>${currentTitle}</title>    <style>        body { font-family: Inter, sans-serif; padding: 40px; max-width: 800px; margin: 0 auto; line-height: 1.6; }        table { border-collapse: collapse; width: 100%; margin-bottom: 1rem; }        th, td { border: 1px solid #ddd; padding: 8px; }        img { max-width: 100%; height: auto; }        blockquote { border-left: 4px solid #ccc; margin: 0; padding-left: 16px; color: #666; }    </style></head><body>    ${currentContent}</body></html>`;
        } else if (exportType === 'doc') {
          data = `<html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'><head><meta charset='utf-8'><title>${currentTitle}</title></head><body>${currentContent}</body></html>`;
          mime = 'application/msword';
          fileExt = 'doc';
        } else if (exportType === 'txt') {
          const temp = document.createElement('div');
          temp.innerHTML = currentContent;
          data = temp.innerText;
          mime = 'text/plain';
          fileExt = 'txt';
        } else if (exportType === 'md') {
          const turndownService = new TurndownService({ headingStyle: 'atx', codeBlockStyle: 'fenced' });
          data = turndownService.turndown(currentContent);
          mime = 'text/markdown';
          fileExt = 'md';
        } else if (exportType === 'json') {
          const docModel = doc.documentModel || htmlToJSONDocument(currentContent, currentTitle, currentConfig);
          data = JSON.stringify(docModel, null, 2);
          mime = 'application/json';
          fileExt = 'json';
        } else if (exportType === 'rtf') {
          const temp = document.createElement('div');
          temp.innerHTML = currentContent;
          data = `{\\rtf1\\ansi\\ansicpg1252\\deff0{\\fonttbl{\\f0\\fnil\\fcharset0 Arial;}}\r\n\\viewkind4\\uc1\\pard\\lang1033\\f0\\fs22 ${temp.innerText.replace(/\n/g, '\\par\r\n')}}`;
          mime = 'application/rtf';
          fileExt = 'rtf';
        }

        const blob = new Blob([data], { type: mime });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `${currentTitle}.${fileExt}`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);

        if (i < docNames.length - 1) {
          await new Promise(resolve => setTimeout(resolve, 600));
        }
      }
    } catch (e) {
      console.error("Batch export error:", e);
    } finally {
      setIsPreparingPrint(false);
    }
  };

  const handleDownloadPDF = async () => {
      setIsPreparingPrint(true);
      try {
          if (exportType === 'pdf') {
              if (documentScope === 'all') {
                  await generatePdfPrint(
                      '', 
                      localConfig, 
                      '', 
                      '', 
                      { 
                          range: 'all',
                          batchPrintContainerId: 'prodoc-batch-print-container'
                      }
                  );
                  closeModal();
              } else {
                  // Ensure we are in print layout mode for correct DOM structure
                  if (viewMode !== 'print') {
                      setViewMode('print');
                      // Wait for view transition
                      await new Promise(resolve => setTimeout(resolve, 500));
                  }

                  // Update global config to match local print settings so the editor reflects the print layout
                  setPageConfig(localConfig);

                  // Wait for editor to re-render with new config
                  await new Promise(resolve => setTimeout(resolve, 800));

                  await generatePdfPrint(
                      content, 
                      localConfig, 
                      headerContent, 
                      footerContent, 
                      { 
                          range: printRange, 
                          pages: customPages,
                          currentPage: currentPage
                      }
                  );
                  closeModal();
              }
          } else {
              if (documentScope === 'all') {
                  await handleBatchExport();
                  closeModal();
              } else {
                  let data = content;
                  let mime = 'text/html';
                  let ext = 'html';
                  if (exportType === 'html') {
                      data = `<!DOCTYPE html><html><head>    <meta charset="utf-8">    <title>${documentTitle}</title>    <style>        body { font-family: Inter, sans-serif; padding: 40px; max-width: 800px; margin: 0 auto; line-height: 1.6; }        table { border-collapse: collapse; width: 100%; margin-bottom: 1rem; }        th, td { border: 1px solid #ddd; padding: 8px; }        img { max-width: 100%; height: auto; }        blockquote { border-left: 4px solid #ccc; margin: 0; padding-left: 16px; color: #666; }    </style></head><body>    ${content}</body></html>`;
                  } else if (exportType === 'doc') {
                      data = `<html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'><head><meta charset='utf-8'><title>${documentTitle}</title></head><body>${content}</body></html>`;
                      mime = 'application/msword';
                      ext = 'doc';
                  } else if (exportType === 'txt') {
                      const temp = document.createElement('div');
                      temp.innerHTML = content;
                      data = temp.innerText;
                      mime = 'text/plain';
                      ext = 'txt';
                  } else if (exportType === 'md') {
                      const turndownService = new TurndownService({ headingStyle: 'atx', codeBlockStyle: 'fenced' });
                      data = turndownService.turndown(content);
                      mime = 'text/markdown';
                      ext = 'md';
                  } else if (exportType === 'json') {
                      const docModel = htmlToJSONDocument(content, documentTitle, pageConfig);
                      data = JSON.stringify(docModel, null, 2);
                      mime = 'application/json';
                      ext = 'json';
                  } else if (exportType === 'rtf') {
                      const temp = document.createElement('div');
                      temp.innerHTML = content;
                      data = `{\\rtf1\\ansi\\ansicpg1252\\deff0{\\fonttbl{\\f0\\fnil\\fcharset0 Arial;}}\r\n\\viewkind4\\uc1\\pard\\lang1033\\f0\\fs22 ${temp.innerText.replace(/\n/g, '\\par\r\n')}}`;
                      mime = 'application/rtf';
                      ext = 'rtf';
                  }
                  const blob = new Blob([data], { type: mime });
                  const url = URL.createObjectURL(blob);
                  const a = document.createElement('a');
                  a.href = url;
                  a.download = `${documentTitle || 'document'}.${ext}`;
                  document.body.appendChild(a);
                  a.click();
                  document.body.removeChild(a);
                  URL.revokeObjectURL(url);
                  closeModal();
              }
          }
      } catch (e) {
          console.error("Export error:", e);
      } finally {
          setIsPreparingPrint(false);
      }
  };

  // Filter pages for preview
  const getFilteredPages = () => {
      if (printRange === 'all') return previewPages;

      if (printRange === 'current') {
          // currentPage is 1-based
          const pageIndex = (currentPage || 1) - 1;
          return previewPages.filter((_, i) => i === pageIndex);
      }

      if (printRange === 'custom') {
          const pagesToShow = new Set<number>();
          const parts = customPages.split(',').map(p => p.trim());

          parts.forEach(part => {
              if (part.includes('-')) {
                  const [start, end] = part.split('-').map(n => parseInt(n, 10));
                  if (!isNaN(start) && !isNaN(end)) {
                      for (let i = start; i <= end; i++) pagesToShow.add(i - 1);
                  }
              } else {
                  const page = parseInt(part, 10);
                  if (!isNaN(page)) pagesToShow.add(page - 1);
              }
          });

          return previewPages.filter((_, i) => pagesToShow.has(i));
      }

      return previewPages;
  };

  const filteredPreviewPages = getFilteredPages();

  return (
    <div 
        className="flex flex-col md:flex-row w-full h-full bg-white dark:bg-slate-950 overflow-hidden md:rounded-2xl"
        onClick={(e) => e.stopPropagation()}
    >
        {isMobile && (
            <div className="flex flex-col bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 shrink-0 z-30">
                <div className="flex items-center justify-between px-4 py-3">
                    <button 
                        onClick={closeModal}
                        className="p-2 -ml-2 text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full"
                    >
                        <ArrowLeft size={20} />
                    </button>
                    <h2 className="text-base font-bold text-slate-800 dark:text-slate-100">Print / Download</h2>
                    <div className="w-8"></div>
                </div>
                <div className="px-4 pb-3">
                    <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-xl">
                        <button 
                            onClick={() => setMobileTab('settings')}
                            className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all flex items-center justify-center gap-2 ${mobileTab === 'settings' ? 'bg-white dark:bg-slate-700 text-blue-600 dark:text-blue-400 shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}
                        >
                            <Sliders size={14} /> Settings
                        </button>
                        <button 
                            onClick={() => setMobileTab('preview')}
                            className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all flex items-center justify-center gap-2 ${mobileTab === 'preview' ? 'bg-white dark:bg-slate-700 text-blue-600 dark:text-blue-400 shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}
                        >
                            <Eye size={14} /> Preview
                        </button>
                    </div>
                </div>
            </div>
        )}

        <div className={`
            w-full md:w-[360px] flex-col border-r border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 shrink-0 z-20 shadow-[4px_0_24px_rgba(0,0,0,0.02)] h-full
            ${isMobile ? (mobileTab === 'settings' ? 'flex' : 'hidden') : 'flex'}
        `}>
            <PrintSettingsPanel 
                localConfig={localConfig}
                setLocalConfig={setLocalConfig}
                copies={copies}
                setCopies={setCopies}
                onPrint={handleDownloadPDF}
                isPreparing={isPreparingPrint}
                closeModal={closeModal}
                isMobile={isMobile}
                printRange={printRange}
                setPrintRange={setPrintRange}
                customPages={customPages}
                setCustomPages={setCustomPages}
                exportType={exportType}
                setExportType={setExportType}
                documentScope={documentScope}
                setDocumentScope={setDocumentScope}
            />
        </div>

        <div className={`
            flex-1 bg-[#525659] dark:bg-slate-950 relative overflow-hidden flex flex-col
            ${isMobile ? (mobileTab === 'preview' ? 'flex' : 'hidden') : 'flex'}
        `}>
            {isMobile ? (
                <MobilePrintPreview 
                    pages={documentScope === 'all' ? allSavedDocsPages : filteredPreviewPages}
                    headerContent={headerContent}
                    footerContent={footerContent}
                    isPreparing={isPreparingPrint}
                    onPrint={handleDownloadPDF}
                    isVisible={mobileTab === 'preview'}
                />
            ) : (
                <DesktopPrintPreview 
                    pages={documentScope === 'all' ? allSavedDocsPages : filteredPreviewPages}
                    headerContent={headerContent}
                    footerContent={footerContent}
                    isPreparing={isPreparingPrint}
                />
            )}
        </div>

        {documentScope === 'all' && createPortal(
            <div id="prodoc-batch-print-container" className="hidden">
                {allSavedDocsPages.map((page, index) => (
                    <div 
                        key={index} 
                        className="prodoc-page-wrapper"
                        style={{
                            pageBreakAfter: 'always',
                            breakAfter: 'page'
                        }}
                    >
                        <div 
                            className="prodoc-page-sheet"
                            style={{
                                width: `${page.widthIn}in`,
                                height: `${page.heightIn}in`,
                                paddingTop: `${page.margins.top}in`,
                                paddingBottom: `${page.margins.bottom}in`,
                                paddingLeft: `${page.margins.left}in`,
                                paddingRight: `${page.margins.right}in`,
                                boxSizing: 'border-box',
                                position: 'relative'
                            }}
                        >
                            <div 
                                className="absolute left-0 right-0 z-30"
                                style={{ 
                                    top: 0, 
                                    height: `${page.margins.top}in`, 
                                    paddingTop: `${page.headerDistance}in`, 
                                    paddingLeft: `${page.margins.left}in`, 
                                    paddingRight: `${page.margins.right}in` 
                                }}
                            >
                                <div 
                                    className="prodoc-header w-full h-full"
                                    dangerouslySetInnerHTML={{ __html: page.headerHtml }}
                                />
                            </div>

                            <div className="relative w-full h-full overflow-hidden z-10">
                                <div 
                                    className="prodoc-editor w-full h-full text-lg leading-loose break-words"
                                    style={{ fontFamily: 'Inter, sans-serif' }}
                                    dangerouslySetInnerHTML={{ __html: page.html }}
                                />
                            </div>

                            <div 
                                className="absolute left-0 right-0 z-30"
                                style={{ 
                                    bottom: 0, 
                                    height: `${page.margins.bottom}in`, 
                                    paddingBottom: `${page.footerDistance}in`, 
                                    paddingLeft: `${page.margins.left}in`, 
                                    paddingRight: `${page.margins.right}in`,
                                    display: 'flex',
                                    flexDirection: 'column',
                                    justifyContent: 'flex-end'
                                }}
                            >
                                <div 
                                    className="prodoc-footer w-full"
                                    dangerouslySetInnerHTML={{ __html: page.footerHtml }}
                                />
                            </div>
                        </div>
                    </div>
                ))}
            </div>,
            document.body
        )}
    </div>
  );
};

import React from 'react';
import { PanelTop, PanelBottom, ArrowRightToLine, ChevronUp, ChevronDown } from 'lucide-react';
import { RibbonSection } from '../../../common/RibbonSection';
import { RibbonButton } from '../../../common/RibbonButton';
import { useEditor } from '../../../../../contexts/EditorContext';

const PositionInput: React.FC<{ label: string; value: number; onChange: (val: number) => void; icon: any }> = ({ label, value, onChange, icon: Icon }) => (
    <div className="flex items-center gap-2">
        <div className="flex items-center gap-1.5 w-[110px] justify-end">
            <Icon size={14} className="text-slate-400"/>
            <span className="text-[10px] text-slate-600 font-medium truncate">{label}:</span>
        </div>
        <div className="flex items-center bg-white border border-slate-300 rounded-sm w-16 h-6 hover:border-blue-400 focus-within:border-blue-500 transition-colors relative group">
            <input 
                type="number" 
                step="0.1" 
                value={value} 
                onChange={(e) => onChange(parseFloat(e.target.value))}
                className="w-full h-full text-xs px-1.5 outline-none text-slate-700 bg-transparent"
            />
            <div className="flex flex-col border-l border-slate-200 w-4 h-full absolute right-0 bg-slate-50 opacity-0 group-hover:opacity-100 transition-opacity">
                <button onClick={() => onChange(Number((value + 0.1).toFixed(1)))} className="flex-1 flex items-center justify-center hover:bg-blue-100 text-slate-500 hover:text-blue-600 transition-colors border-b border-slate-200">
                    <ChevronUp size={6} strokeWidth={3} />
                </button>
                <button onClick={() => onChange(Number((Math.max(0, value - 0.1)).toFixed(1)))} className="flex-1 flex items-center justify-center hover:bg-blue-100 text-slate-500 hover:text-blue-600 transition-colors">
                    <ChevronDown size={6} strokeWidth={3} />
                </button>
            </div>
            <span className="absolute right-5 text-[10px] text-slate-400 pointer-events-none">"</span>
        </div>
    </div>
);

export const PositionGroup: React.FC = () => {
  const { pageConfig, setPageConfig } = useEditor();

  return (
    <RibbonSection title="Position">
        <div className="flex h-full gap-2 items-center px-1">
            <div className="flex flex-col gap-1 justify-center h-full">
                <PositionInput 
                    label="Header from Top" 
                    value={pageConfig.headerDistance || 0.5} 
