      verticalAlign: position === 'normal' ? 'baseline' : position === 'raised' ? 'super' : 'sub',
      fontFeatureSettings: ligatures === 'none' ? '"liga" 0' : '"liga" 1',
      transform: scale !== 100 ? `scaleX(${scale / 100})` : undefined,
