                            options={[
                                { value: 'top', label: 'Top' },
                                { value: 'center', label: 'Center' },
                                { value: 'justify', label: 'Justified' },
                                { value: 'bottom', label: 'Bottom' },
                            ]}
                        />
                    </div>
                )}

                {layoutSubTab === 'apply' && <ApplyToSection localConfig={localConfig} setLocalConfig={setLocalConfig} />}
            </div>
        </>
    );
};

import React, { useState, useEffect } from 'react';
import { X, LayoutTemplate, Monitor } from 'lucide-react';
import { PageConfig } from '../../../../../../../types';
import { MarginTab } from './PageSetupDialog/margin';
import { PaperTab } from '../../size/MorePageSizes/PageSetupDialog/pager';
import { LayoutTab } from '../../LineNumbers/LineNumberingOptions/PageSetupDialog/layout';

interface PageSetupDialogProps {
  isOpen: boolean;
  onClose: () => void;
  config: PageConfig;
  onSave: (config: PageConfig) => void;
}

type Tab = 'margins' | 'paper' | 'layout';

export const PageSetupDialog: React.FC<PageSetupDialogProps> = ({
  isOpen,
  onClose,
  config,
  onSave
}) => {
  const [activeTab, setActiveTab] = useState<Tab>('margins');
  const [localConfig, setLocalConfig] = useState<PageConfig>(config);

  useEffect(() => {
    if (isOpen) {
      const t = setTimeout(() => {
        setLocalConfig(JSON.parse(JSON.stringify(config)));
      }, 0);
      return () => clearTimeout(t);
    }
  }, [isOpen, config]);

  if (!isOpen) return null;

  const renderPreview = () => {
    const { orientation, multiplePages, margins, gutterPosition } = localConfig;
    const isPortrait = orientation === 'portrait';
    const isMirroredOrBookFold = ['mirrorMargins', 'bookFold'].includes(multiplePages || '');
    const hasGutter = (margins.gutter || 0) > 0;

    const baseWidth = isPortrait ? 80 : 110;
    const baseHeight = isPortrait ? 110 : 80;

    const marginScale = 6; 
    const previewMargins = {
      top: margins.top * marginScale,
      bottom: margins.bottom * marginScale,
      left: margins.left * marginScale,
      right: margins.right * marginScale,
      gutter: (margins.gutter || 0) * marginScale
    };

    let effectiveLeft = previewMargins.left;
    const effectiveRight = previewMargins.right;
    let effectiveTop = previewMargins.top;

    if (!isMirroredOrBookFold && hasGutter) {
        if (gutterPosition === 'left') {
            effectiveLeft += previewMargins.gutter;
        } else { 
            effectiveTop += previewMargins.gutter;
        }
    }

    const SkeletonContent = () => (
        <div className="w-full h-full flex flex-col gap-[3px] overflow-hidden opacity-60">
            <div className="w-3/4 h-[2px] bg-slate-300 rounded-full mb-[2px]"></div>
            <div className="w-full h-[1px] bg-slate-200 rounded-full"></div>
            <div className="w-full h-[1px] bg-slate-200 rounded-full"></div>
            <div className="w-5/6 h-[1px] bg-slate-200 rounded-full"></div>
            <div className="w-full h-[1px] bg-slate-200 rounded-full mt-[2px]"></div>
            <div className="w-full h-[1px] bg-slate-200 rounded-full"></div>
            <div className="w-4/5 h-[1px] bg-slate-200 rounded-full"></div>
            <div className="w-1/2 h-[1px] bg-slate-200 rounded-full mt-[2px]"></div>
        </div>
    );

    const GutterPattern = () => (
        <div 
            className="absolute bg-slate-300/30 z-10 h-full w-full"
            style={{
                backgroundImage: 'repeating-linear-gradient(45deg, transparent, transparent 2px, #cbd5e1 2px, #cbd5e1 3px)',
            }}
        />
    );

    const PageSheet = ({ children, style }: any) => (
        <div 
            className="bg-white relative shadow-[0_4px_12px_-2px_rgba(0,0,0,0.12),0_2px_6px_-1px_rgba(0,0,0,0.08)] transition-all duration-300 ease-out ring-1 ring-black/[0.03]"
            style={{
                ...style,
                borderRadius: '2px' 
            }}
        >
            {children}
        </div>
    );

    const SinglePagePreview = (
        <PageSheet style={{ width: `${baseWidth}px`, height: `${baseHeight}px` }}>
            <div 
                className="absolute border-[0.5px] border-dashed border-blue-300/60 flex flex-col justify-evenly px-[2px] py-[2px] transition-all duration-300"
                style={{
                    top: `${effectiveTop}px`,
                    bottom: `${previewMargins.bottom}px`,
                    left: `${effectiveLeft}px`,
                    right: `${effectiveRight}px`,
                    backgroundColor: 'rgba(59, 130, 246, 0.02)'
                }}
            >
                <SkeletonContent />
            </div>

            {hasGutter && gutterPosition === 'left' && !isMirroredOrBookFold && (
                <div className="absolute top-0 bottom-0 left-0" style={{width: `${previewMargins.gutter}px`}}>
                    <GutterPattern />
                </div>
            )}
            {hasGutter && gutterPosition === 'top' && !isMirroredOrBookFold && (
                <div className="absolute left-0 right-0 top-0" style={{height: `${previewMargins.gutter}px`}}>
                    <GutterPattern />
                </div>
            )}
        </PageSheet>
    );

    const TwoPagePreview = (
        <div className="flex items-center justify-center gap-[1px]">
            {/* Left Page */}
            <PageSheet style={{ width: `${baseWidth}px`, height: `${baseHeight}px` }}>
                <div 
                    className="absolute border-[0.5px] border-dashed border-blue-300/60 flex flex-col justify-evenly px-[2px] py-[2px]"
                    style={{
                        top: `${previewMargins.top}px`,
                        bottom: `${previewMargins.bottom}px`,
                        left: `${previewMargins.right}px`,
                        right: `${previewMargins.left + (hasGutter && gutterPosition === 'left' ? previewMargins.gutter : 0)}px`,
                        backgroundColor: 'rgba(59, 130, 246, 0.02)'
                    }}
                >
                    <SkeletonContent />
                </div>
                 {hasGutter && gutterPosition === 'left' && (
                    <div className="absolute top-0 bottom-0 right-0 border-l border-slate-300/50" style={{width: `${previewMargins.gutter}px`, right: `${previewMargins.left}px`}}>
                        <GutterPattern />
                    </div>
                )}
            </PageSheet>

            {/* Spine/Binding Effect */}
            <div className="w-[2px] h-[95%] bg-gradient-to-b from-slate-300 via-slate-400 to-slate-300 shadow-sm z-10 rounded-full"></div>

            {/* Right Page */}
            <PageSheet style={{ width: `${baseWidth}px`, height: `${baseHeight}px` }}>
                <div 
                    className="absolute border-[0.5px] border-dashed border-blue-300/60 flex flex-col justify-evenly px-[2px] py-[2px]"
                    style={{
                        top: `${previewMargins.top}px`,
                        bottom: `${previewMargins.bottom}px`,
                        left: `${previewMargins.left + (hasGutter && gutterPosition === 'left' ? previewMargins.gutter : 0)}px`,
                        right: `${previewMargins.right}px`,
                        backgroundColor: 'rgba(59, 130, 246, 0.02)'
                    }}
                >
                    <SkeletonContent />
                </div>
                 {hasGutter && gutterPosition === 'left' && (
                    <div className="absolute top-0 bottom-0 left-0 border-r border-slate-300/50" style={{width: `${previewMargins.gutter}px`, left: `${previewMargins.left}px`}}>
                        <GutterPattern />
                    </div>
                )}
            </PageSheet>
        </div>
    );

    if (['mirrorMargins', 'bookFold', 'twoPagesPerSheet'].includes(multiplePages || '')) {
        return TwoPagePreview;
    }
    return SinglePagePreview;
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/40 backdrop-blur-md p-4 animate-in fade-in duration-200">
      <div 
        className="bg-white dark:bg-slate-900 w-[95vw] md:w-[50vw] lg:w-[30vw] max-w-[450px] h-auto max-h-[85vh] md:max-h-[630px] rounded-2xl shadow-2xl border border-white/50 dark:border-slate-700 flex flex-col overflow-hidden animate-in zoom-in-95 duration-200 ring-1 ring-black/5"
        onClick={e => e.stopPropagation()}
      >
        {/* Header */}
        <div className="flex items-center justify-between px-5 py-4 border-b border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900 shrink-0">
            <h2 className="text-sm font-bold text-slate-800 dark:text-slate-100 tracking-tight flex items-center gap-2">
                <div className="p-1.5 bg-blue-50 dark:bg-slate-800 rounded-md text-blue-600 dark:text-blue-400">
                    <LayoutTemplate size={16} /> 
                </div>
                Page Setup
            </h2>
            <button 
                onClick={onClose} 
                className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 transition-colors p-1.5 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full"
            >
                <X size={18} />
            </button>
        </div>

        {/* Main Tabs */}
        <div className="px-5 pt-4 pb-2 bg-white dark:bg-slate-900 shrink-0">
            <div className="flex p-1 bg-slate-100 dark:bg-slate-800 rounded-xl">
                {['margins', 'paper', 'layout'].map((tab) => (
                    <button
                        key={tab}
                        onClick={() => setActiveTab(tab as Tab)}
                        className={`flex-1 py-1.5 text-[11px] font-bold uppercase tracking-wide rounded-lg transition-all duration-300 ${activeTab === tab ? 'bg-white dark:bg-slate-700 text-blue-600 dark:text-blue-300 shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-200'}`}
                    >
                        {tab}
                    </button>
                ))}
            </div>
        </div>

        {/* Content Container */}
        <div className="flex-1 flex flex-col overflow-hidden relative">

            {/* Beautiful Preview Section */}
            <div className="px-5 pt-2 pb-4 shrink-0 relative z-0">
                 <div className="w-full h-[20vh] min-h-[140px] rounded-xl border border-slate-200 dark:border-slate-700 relative overflow-hidden flex items-center justify-center shadow-inner group"
                      style={{
                          backgroundColor: '#f1f5f9',
                          backgroundImage: 'linear-gradient(#e2e8f0 1px, transparent 1px), linear-gradient(90deg, #e2e8f0 1px, transparent 1px)',
                          backgroundSize: '20px 20px'
                      }}
                 >
                     <div className="absolute inset-0 bg-gradient-to-t from-slate-100/50 to-transparent pointer-events-none"></div>
                     <div className="relative z-10 transform transition-transform group-hover:scale-[1.02] duration-500 perspective-1000">
                        {renderPreview()}
                     </div>
                     <div className="absolute bottom-2 right-3 text-[10px] font-semibold text-slate-400/80 bg-white/60 px-2 py-0.5 rounded-full backdrop-blur-sm border border-white/50 shadow-sm pointer-events-none">
                        PREVIEW
                     </div>
                 </div>
            </div>

            {/* Scrollable Settings Area */}
            <div className="flex-1 overflow-y-auto px-5 pb-4 scrollbar-thin scrollbar-thumb-slate-200 dark:scrollbar-thumb-slate-700 hover:scrollbar-thumb-slate-300">
                {activeTab === 'margins' && (
                    <MarginTab localConfig={localConfig} setLocalConfig={setLocalConfig} />
                )}

                {activeTab === 'paper' && (
                    <PaperTab localConfig={localConfig} setLocalConfig={setLocalConfig} />
                )}

                {activeTab === 'layout' && (
                    <LayoutTab localConfig={localConfig} setLocalConfig={setLocalConfig} />
                )}
            </div>
        </div>

        {/* Footer */}
        <div className="flex items-center justify-between px-5 py-4 bg-slate-50 dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800 shrink-0">
            <button 
                onClick={() => alert("Defaults not yet implemented.")}
                className="text-xs font-semibold text-slate-500 hover:text-blue-600 transition-colors flex items-center gap-1.5 group"
            >
                <Monitor size={14} className="group-hover:scale-110 transition-transform"/> Set As Default
            </button>
            <div className="flex gap-3">
                <button 
                    onClick={onClose} 
                    className="px-4 py-2 text-xs font-bold text-slate-600 dark:text-slate-300 hover:bg-white dark:hover:bg-slate-800 hover:text-slate-800 dark:hover:text-white border border-transparent hover:border-slate-200 dark:hover:border-slate-700 rounded-lg transition-all"
                >
                    Cancel
                </button>
                <button 
                    onClick={() => { onSave(localConfig); onClose(); }} 
                    className="px-6 py-2 bg-blue-600 dark:bg-blue-500 hover:bg-blue-700 dark:hover:bg-blue-600 text-white text-xs font-bold rounded-lg shadow-md hover:shadow-lg shadow-blue-200 dark:shadow-none transition-all active:scale-95"
                >
                    OK
                </button>
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { FileText, Check } from 'lucide-react';
import { CompactInput, CompactSelect, ApplyToSection, RenderSubTabs } from '../../../common/DialogHelpers';
import { PageConfig, PageOrientation, MultiplePagesType, SheetsPerBookletType } from '../../../../../../../../types';
import { PAGE_SIZES } from '../../../../../../../../constants';

interface MarginTabProps {
    localConfig: PageConfig;
    setLocalConfig: React.Dispatch<React.SetStateAction<PageConfig>>;
}

type MarginSubTab = 'margins' | 'orientation' | 'pages' | 'apply';

export const MarginTab: React.FC<MarginTabProps> = ({ localConfig, setLocalConfig }) => {
    const [marginSubTab, setMarginSubTab] = useState<MarginSubTab>('margins');

    const handleMarginInputChange = (section: keyof PageConfig['margins'], value: string) => {
        let numVal = parseFloat(value);
        if (isNaN(numVal)) numVal = 0;
        if (numVal < 0) numVal = 0;

        setLocalConfig(prev => ({
          ...prev,
          marginPreset: 'custom',
          margins: {
            ...prev.margins,
            [section]: numVal
          }
        }));
    };

    const handleOrientationChange = (orientation: PageOrientation) => {
        if (orientation !== localConfig.orientation) {
            let currentWidth = localConfig.customWidth;
            let currentHeight = localConfig.customHeight;

            if (localConfig.size !== 'Custom' || !currentWidth || !currentHeight) {
                 const base = PAGE_SIZES[localConfig.size as string] || PAGE_SIZES.Letter;
                 currentWidth = base.width / 96;
                 currentHeight = base.height / 96;
            }

            const newWidth = currentHeight;
            const newHeight = currentWidth;

            setLocalConfig(prev => ({
                ...prev,
                orientation,
                customWidth: newWidth,
                customHeight: newHeight,
                size: 'Custom' 
            }));
        }
    };

    const handleMultiplePagesChange = (type: MultiplePagesType) => {
        setLocalConfig(prev => ({
            ...prev,
            multiplePages: type,
            mirrorMargins: type === 'mirrorMargins' || type === 'bookFold'
        }));
    };

    return (
        <>
            <RenderSubTabs tabs={['margins', 'orientation', 'pages', 'apply']} active={marginSubTab} setActive={setMarginSubTab} />
            <div className="animate-in slide-in-from-right-4 duration-300 fade-in pt-2">
                {marginSubTab === 'margins' && (
                    <div className="flex flex-col gap-4">
                        <div className="grid grid-cols-2 gap-3">
                            <CompactInput label="Top" value={localConfig.margins.top} onChange={(e: any) => handleMarginInputChange('top', e.target.value)} />
                            <CompactInput label="Bottom" value={localConfig.margins.bottom} onChange={(e: any) => handleMarginInputChange('bottom', e.target.value)} />
                            <CompactInput label={localConfig.multiplePages === 'mirrorMargins' || localConfig.multiplePages === 'bookFold' ? 'Inside' : 'Left'} value={localConfig.margins.left} onChange={(e: any) => handleMarginInputChange('left', e.target.value)} />
                            <CompactInput label={localConfig.multiplePages === 'mirrorMargins' || localConfig.multiplePages === 'bookFold' ? 'Outside' : 'Right'} value={localConfig.margins.right} onChange={(e: any) => handleMarginInputChange('right', e.target.value)} />
                        </div>
                        <div className="grid grid-cols-2 gap-3 pt-3 border-t border-slate-100 dark:border-slate-800">
                            <CompactInput label="Gutter" value={localConfig.margins.gutter} onChange={(e: any) => handleMarginInputChange('gutter', e.target.value)} />
                            <CompactSelect
                                label="Position"
                                value={localConfig.gutterPosition}
                                onChange={(e: any) => setLocalConfig(prev => ({ ...prev, gutterPosition: e.target.value }))}
                                options={[
                                    { value: 'left', label: 'Left' },
                                    { value: 'top', label: 'Top' },
                                ]}
                            />
                        </div>
                    </div>
                )}

                {marginSubTab === 'orientation' && (
                    <div className="flex flex-col h-full">
                        <div className="flex-1 flex gap-4 items-center justify-center min-h-[200px]">
                                <button 
                                onClick={() => handleOrientationChange('portrait')}
                                className={`flex-1 min-w-0 h-full max-h-[240px] flex flex-col items-center justify-center p-6 rounded-2xl border-1 transition-all duration-300 group relative overflow-hidden ${localConfig.orientation === 'portrait' ? 'bg-blue-50 dark:bg-blue-900/20 border-blue-600 dark:border-blue-500 text-blue-700 dark:text-blue-300 shadow-md' : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-500 hover:border-blue-300 dark:hover:border-blue-600 hover:bg-slate-50 hover:shadow-sm'}`}
                                >
                                <div className={`mb-4 p-5 rounded-full transition-transform duration-300 group-hover:scale-110 shadow-sm ${localConfig.orientation === 'portrait' ? 'bg-blue-100 dark:bg-blue-800 text-blue-600 dark:text-blue-300' : 'bg-slate-100 dark:bg-slate-700 text-slate-400 group-hover:bg-blue-100 dark:group-hover:bg-blue-900/50 group-hover:text-blue-600'}`}>
                                    <FileText size={32} strokeWidth={1.5} />
                                </div>
                                <span className="text-base font-bold tracking-tight">Portrait</span>
                                {localConfig.orientation === 'portrait' && <div className="absolute top-3 right-3 w-2.5 h-2.5 bg-blue-600 rounded-full animate-in zoom-in"></div>}
                                </button>

                                <button 
                                onClick={() => handleOrientationChange('landscape')}
                                className={`flex-1 min-w-0 h-full max-h-[240px] flex flex-col items-center justify-center p-6 rounded-2xl border-1 transition-all duration-300 group relative overflow-hidden ${localConfig.orientation === 'landscape' ? 'bg-blue-50 dark:bg-blue-900/20 border-blue-600 dark:border-blue-500 text-blue-700 dark:text-blue-300 shadow-md' : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-500 hover:border-blue-300 dark:hover:border-blue-600 hover:bg-slate-50 hover:shadow-sm'}`}
                                >
                                <div className={`mb-4 p-5 rounded-full transition-transform duration-300 group-hover:scale-110 shadow-sm ${localConfig.orientation === 'landscape' ? 'bg-blue-100 dark:bg-blue-800 text-blue-600 dark:text-blue-300' : 'bg-slate-100 dark:bg-slate-700 text-slate-400 group-hover:bg-blue-100 dark:group-hover:bg-blue-900/50 group-hover:text-blue-600'}`}>
                                    <FileText size={32} className="rotate-90" strokeWidth={1.5} />
                                </div>
                                <span className="text-base font-bold tracking-tight">Landscape</span>
                                {localConfig.orientation === 'landscape' && <div className="absolute top-3 right-3 w-2.5 h-2.5 bg-blue-600 rounded-full animate-in zoom-in"></div>}
                                </button>
                        </div>
                        <div className="mt-4 text-center text-xs text-slate-400 font-medium">
                            {localConfig.orientation === 'portrait' ? 'Standard vertical orientation.' : 'Wide horizontal orientation.'}
                        </div>
                    </div>
                )}

                {marginSubTab === 'pages' && (
                    <div className="flex flex-col gap-4">
                        <div className="grid grid-cols-1 gap-4">
                            <CompactSelect
                                label="Multiple pages"
                                value={localConfig.multiplePages}
                                onChange={(e: any) => handleMultiplePagesChange(e.target.value)}
                                options={[
                                    { value: 'normal', label: 'Normal' },
                                    { value: 'mirrorMargins', label: 'Mirror margins' },
                                    { value: 'bookFold', label: 'Book fold' },
                                    { value: 'twoPagesPerSheet', label: '2 pages per sheet' },
                                ]}
                            />
                            {localConfig.multiplePages === 'bookFold' && (
                                <div className="animate-in slide-in-from-top-2 fade-in">
                                    <CompactSelect
                                        label="Sheets per booklet"
                                        value={localConfig.sheetsPerBooklet}
                                        onChange={(e: any) => setLocalConfig(prev => ({ ...prev, sheetsPerBooklet: e.target.value as SheetsPerBookletType }))}
                                        options={[
                                            { value: 'all', label: 'All' },
                                            { value: '16', label: '16' },
                                            { value: '8', label: '8' },
                                            { value: '4', label: '4' },
                                            { value: '2', label: '2' },
                                        ]}
                                    />
                                </div>
                            )}
                        </div>
                    </div>
                )}

                {marginSubTab === 'apply' && <ApplyToSection localConfig={localConfig} setLocalConfig={setLocalConfig} />}
            </div>
        </>
    );
};

import React, { useState, Suspense, useMemo } from 'react';
import { LayoutTemplate, Columns, ArrowLeftRight, MoveVertical, ArrowRightLeft, Monitor, Settings2 } from 'lucide-react';
import { useEditor } from '../../../../../../contexts/EditorContext';
import { useLayoutTab } from '../../LayoutTabContext';
import { DropdownButton } from '../../common/LayoutTools';
import { MenuPortal } from '../../../../common/MenuPortal';
import { MARGIN_PRESETS } from '../../../../../../constants';
import { MarginPreset, MarginValues } from '../../../../../../types';

export const MarginsTool: React.FC = () => {
  const { setPageConfig, pageConfig, setShowPageSetup } = useEditor();
  const { activeMenu, menuPos, closeMenu } = useLayoutTab();
  const menuId = 'margins';

  const handleMarginChange = (preset: MarginPreset) => {
      if (preset !== 'custom') {
          const isMirrored = preset === 'mirrored';
          setPageConfig(prev => ({ 
              ...prev, 
              marginPreset: preset,
              margins: MARGIN_PRESETS[preset as string],
              mirrorMargins: isMirrored
          }));
      }
      closeMenu();
  };

  const openCustomDialog = () => {
      closeMenu();
      setShowPageSetup(true);
  };

  const formatLabel = (key: string) => {
      if (key === 'classic') return 'Classic Default';
      if (key === 'apa') return 'APA';
      if (key === 'mla') return 'MLA';
      if (key === 'chicago') return 'Chicago';

      const result = key.replace(/([A-Z])/g, " $1");
      return result.charAt(0).toUpperCase() + result.slice(1);
  };

  const marginOptions = useMemo(() => (Object.entries(MARGIN_PRESETS) as [string, MarginValues][]).map(([key, val]) => {
      let icon = LayoutTemplate;
      let colorClass = "text-slate-400";

      if (key === 'normal') { colorClass = "text-blue-500"; }
      if (key === 'narrow') { icon = Columns; colorClass = "text-emerald-500"; }
      if (key === 'moderate') { icon = MoveVertical; colorClass = "text-orange-500"; }
      if (key === 'wide') { icon = ArrowLeftRight; colorClass = "text-purple-500"; }
      if (key === 'mirrored') { icon = ArrowRightLeft; colorClass = "text-indigo-500"; }
      if (key === 'classic') { icon = Monitor; colorClass = "text-sky-500"; }

      return {
        id: key,
        label: formatLabel(key),
        desc: `Top ${val.top}" Bottom ${val.bottom}" Left ${val.left}" Right ${val.right}"`,
        icon,
        colorClass
      };
  }), []);

  return (
    <>
         <DropdownButton 
             id={menuId} 
             icon={LayoutTemplate} 
             label="Margins" 
             iconClassName="text-cyan-600 dark:text-cyan-500"
         />
         <MenuPortal id={menuId} activeMenu={activeMenu} menuPos={menuPos} closeMenu={closeMenu} width={280}>
             <div className="p-1 space-y-0.5 max-h-[60vh] overflow-y-auto scrollbar-thin scrollbar-thumb-slate-200">
                 {marginOptions.map((option) => (
                     <button 
                        key={option.id}
                        onClick={() => handleMarginChange(option.id as MarginPreset)}
                        onMouseDown={(e) => e.preventDefault()}
                        className={`w-full text-left px-3 py-2 hover:bg-slate-100 rounded-md flex items-center gap-3 group transition-colors ${pageConfig.marginPreset === option.id ? 'bg-blue-50 text-blue-700 ring-1 ring-blue-200' : 'text-slate-700'}`}
                     >
                         <option.icon size={18} className={`flex-shrink-0 ${pageConfig.marginPreset === option.id ? 'text-blue-500' : option.colorClass}`} strokeWidth={1.5} />
                         <div className="flex-1 min-w-0">
                            <div className="text-xs font-medium truncate">{option.label}</div>
                            <div className={`text-[10px] truncate ${pageConfig.marginPreset === option.id ? 'text-blue-400' : 'text-slate-400'}`}>{option.desc}</div>
                         </div>
                         {pageConfig.marginPreset === option.id && (
                             <div className="w-1.5 h-1.5 rounded-full bg-blue-600 ml-2 shrink-0" />
                         )}
                     </button>
                 ))}

                 <div className="border-t border-slate-100 my-1"></div>

                 <button 
                    className="w-full text-left px-3 py-2 hover:bg-slate-100 text-xs font-medium text-slate-700 rounded-md flex items-center gap-3 group transition-colors" 
                    onClick={openCustomDialog}
                    onMouseDown={(e) => e.preventDefault()}
                 >
                    <Settings2 size={18} className="text-slate-400 group-hover:text-slate-600" strokeWidth={1.5} />
                    <span>Custom Margins...</span>
                 </button>
             </div>
         </MenuPortal>
    </>
  );
};

import React from 'react';
