    registerContainer,
    showRuler,
    setShowRuler,
    documentTitle,
    setDocumentTitle,
    lastModified,
    setLastModified,
    creationDate,
    showFormattingMarks,
    setShowFormattingMarks,
    customStyles: [] as CustomStyle[],
    addCustomStyle,
    applyCustomStyle,
    applyAdvancedStyle: applyAdvancedStyleCallback,
    applyBlockStyle: applyBlockStyleCallback,
    handlePasteSpecial,
    activeElementType,
    setActiveElementType,
    currentPage,
