    isAIProcessing: aiState !== 'idle',
    setIsAIProcessing,
    activeEditingArea,
    setActiveEditingArea,
    headerContent,
    setHeaderContent,
    footerContent,
    setFooterContent,
    firstHeaderContent,
    setFirstHeaderContent,
    firstFooterContent,
    setFirstFooterContent,
    isKeyboardLocked,
    isTableResizerEnabled,
    isTableResizing,
    setIsTableResizing,
    setIsTableResizerEnabled,
    setIsKeyboardLocked,
    selectionMode,
    setSelectionMode,
    hasActiveSelection,
    selectionAction,
    setSelectionAction,
    importState,
    importFile,
