import { AIOperation, PageConfig } from '../types';
import { generateAIContent, streamAIContent } from '../services/geminiService';
import { useEditor } from '../contexts/EditorContext';
import { jsonToHtml, safeJsonParse } from '../utils/documentConverter';

export interface AIOptions {
  mode?: 'insert' | 'replace' | 'edit';
  useSelection?: boolean;
}

// Helper to convert units
const parseDimension = (val: string | number | undefined): number => {
    if (val === undefined || val === null) return 1; 
    if (typeof val === 'number') return val;

    const str = val.toLowerCase().trim();
    const num = parseFloat(str);
    if (isNaN(num)) return 1;

    if (str.endsWith('cm')) return num / 2.54;
    if (str.endsWith('mm')) return num / 25.4;
    if (str.endsWith('in') || str.endsWith('"')) return num;
    if (str.endsWith('pt')) return num / 72;
    if (str.endsWith('px')) return num / 96;

    return num; 
};

export const useAI = () => {
  const { 
      executeCommand, 
      editorRef, 
      setContent, 
      isAIProcessing, 
      setIsAIProcessing, 
      setAiState, 
      content,
      setHeaderContent,
      setFooterContent,
      setPageConfig
  } = useEditor();

  const performAIAction = async (
    operation: string, 
    customInput?: string, 
    options: AIOptions = { mode: 'insert' },
    restoreRange?: Range | null
  ) => {
    console.log(`[useAI] Action: ${operation}, Mode: ${options.mode}`);

    let activeRange: Range | null = restoreRange || null;

    // Auto-detect range if insert/edit mode
    if (!activeRange && options.mode !== 'replace') {
        const sel = window.getSelection();
        if (sel && sel.rangeCount > 0) {
            activeRange = sel.getRangeAt(0).cloneRange();
        }
    }

    // Context Extraction
    const selection = window.getSelection();
    const hasSelection = selection && selection.rangeCount > 0 && !selection.isCollapsed;
    let textToProcess = hasSelection ? selection.toString() : "";

    // If 'Insert' and prompt provided, we might want context from doc or just blank
    if (operation === 'generate_content') {
        if (!customInput) {
            alert("Please provide a prompt.");
            return;
        }
        if (options.mode === 'insert') textToProcess = content || ""; 
        else if (options.mode === 'replace') textToProcess = "";
    } 

    // If 'Refine' (Edit) and no selection, fallback to full doc
    else if (operation === 'edit_content' && !textToProcess) {
        if (content && content.trim().length > 0) {
             textToProcess = editorRef.current?.innerText || ""; // Use text content for context
             // Select entire document for replacement
             if (editorRef.current) {
                 const range = document.createRange();
                 range.selectNodeContents(editorRef.current);
                 activeRange = range; // Update target range to full doc
             }
        } else {
             alert("Please select text or ensure document has content to refine.");
             return;
        }
    }

    const expectsJson = 
        operation === 'generate_content' || 
        operation === 'edit_content' ||
        operation === 'continue_writing' || 
        operation === 'expand' || 
        operation === 'shorten' ||
        operation === 'simplify' ||
        operation === 'fix_grammar' ||
        operation === 'make_professional' ||
        operation === 'generate_outline' ||
        operation.startsWith('tone_');

    setAiState('thinking');

    try {
        if (expectsJson) {
            const jsonString = await generateAIContent(operation as AIOperation, textToProcess, customInput);

            setAiState('writing');

            let parsedData;
            try {
                parsedData = safeJsonParse(jsonString);
            } catch (e) {
                console.error("JSON Parse Error:", e);
                alert("The AI response structure was invalid. Please try again or refine your prompt.");
                setAiState('idle');
                return;
            }

            if (parsedData.error) {
                alert("AI Error: " + parsedData.error);
                setAiState('idle');
                return;
            }

            if (options.mode === 'replace') {
                // Full Document Replacement - Clear Existing State

                // Handle Document Settings
                const docSettings = parsedData.document?.settings || {};
                let blocks = parsedData.document?.blocks || parsedData.blocks || [];
                if (!Array.isArray(blocks)) blocks = [];

                const settingsBlockIndex = blocks.findIndex((b: any) => b.type === 'page_settings');
                let blockSettings = {};
                if (settingsBlockIndex !== -1) {
                    blockSettings = blocks[settingsBlockIndex];
                    blocks.splice(settingsBlockIndex, 1);
                }

                const mergedSettings = { ...docSettings, ...blockSettings };

                if (Object.keys(mergedSettings).length > 0) {
                    setPageConfig((prev: PageConfig) => ({
                        ...prev,
                        size: mergedSettings.size || mergedSettings.pageSize || prev.size,
                        orientation: mergedSettings.orientation || prev.orientation,
                        margins: mergedSettings.margins ? {
                            ...prev.margins,
                            top: parseDimension(mergedSettings.margins.top),
                            bottom: parseDimension(mergedSettings.margins.bottom),
                            left: parseDimension(mergedSettings.margins.left),
                            right: parseDimension(mergedSettings.margins.right)
                        } : prev.margins,
                    }));
                }

                // Handle Headers/Footers - Reset if missing to ensure clean slate
                const headers = parsedData.document?.headers || parsedData.document?.header;
                if (headers) {
                    const defaultHeader = Array.isArray(headers) ? headers : (headers.default || headers.first);
                    if (defaultHeader) setHeaderContent(jsonToHtml({ blocks: defaultHeader }));
                } else {
                    setHeaderContent('<div style="color: #94a3b8;">[Header]</div>');
                }

                const footers = parsedData.document?.footers || parsedData.document?.footer;
                if (footers) {
                    const defaultFooter = Array.isArray(footers) ? footers : (footers.default || footers.first);
                    if (defaultFooter) setFooterContent(jsonToHtml({ blocks: defaultFooter }));
                } else {
                    setFooterContent('<div style="color: #94a3b8;">[Page <span class="page-number-placeholder">1</span>]</div>');
                }

                // Render Body - Completely Replace
                const bodyHtml = jsonToHtml({ blocks });

                // Use setContent to fully reset editor state/history
                setContent(bodyHtml, true);

                // If possible, focus start
                if (editorRef.current) {
                    editorRef.current.scrollTop = 0;
                }

            } else {
                // Insert/Edit Mode
                const contentData = parsedData;
                let blocks = contentData.document?.blocks || contentData.blocks || (Array.isArray(contentData) ? contentData : [contentData]);

                blocks = blocks.filter((b: any) => b.type !== 'page_settings');
                const html = jsonToHtml(blocks);

                // Restore range/cursor before insertion
                if (activeRange) {
                    const sel = window.getSelection();
                    if (sel) {
                        sel.removeAllRanges();
                        sel.addRange(activeRange);
                    }
                } else if (editorRef.current) {
                    editorRef.current.focus();
                }

                executeCommand('insertHTML', html);
            }

        } else {
            // Streaming Mode (Legacy/Simple)
            if (activeRange) {
                 const sel = window.getSelection();
                 if (sel) {
                     sel.removeAllRanges();
                     sel.addRange(activeRange);
                 }
            }

            const stream = streamAIContent(operation as AIOperation, textToProcess, customInput);
            let isFirst = true;

            for await (const chunk of stream) {
                if (isFirst) {
                    setAiState('writing');
                    document.execCommand('insertText', false, chunk);
                    isFirst = false;
                } else {
                    document.execCommand('insertText', false, chunk);
                }
            }
        }

    } catch (e) {
        console.error("[useAI] Error:", e);
        alert("AI processing failed. Please check your API key.");
    } finally {
        setAiState('idle');
    }
  };

  return { isProcessing: isAIProcessing, performAIAction };
};

import { useState, useRef, useCallback } from 'react';
import { SaveStatus, PageConfig, DocumentFootnote, DocumentEndnote } from '../types';
import { htmlToJSONDocument } from '../utils/documentModel';

export const useAutoSave = () => {
  const [saveStatus, setSaveStatus] = useState<SaveStatus>('saved');
  const autoSaveTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const triggerAutoSave = useCallback((title: string, content: string, pageConfig: PageConfig, footnotes?: DocumentFootnote[], endnotes?: DocumentEndnote[]) => {
    setSaveStatus('unsaved');

    if (autoSaveTimerRef.current) {
      clearTimeout(autoSaveTimerRef.current);
    }

    // Debounce save
    autoSaveTimerRef.current = setTimeout(() => {
      setSaveStatus('saving');

      try {
        // Convert to Structured JSON document model
        const docModel = htmlToJSONDocument(content, title, pageConfig, undefined, undefined, footnotes, endnotes);

        // Save to localStorage
        const savedDocs = JSON.parse(localStorage.getItem('saved_documents') || '{}');
        savedDocs[title] = {
          documentModel: docModel,
          content, // Fallback content
          lastModified: new Date().toISOString(),
        };
        localStorage.setItem('saved_documents', JSON.stringify(savedDocs));

        // Update recent_documents
        let recents = JSON.parse(localStorage.getItem('recent_documents') || '[]');
        recents = recents.filter((r: any) => r.name !== title);
        recents.unshift({
          name: title,
          date: new Date().toLocaleDateString() + ' ' + new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
          path: 'Local Storage'
        });
        localStorage.setItem('recent_documents', JSON.stringify(recents.slice(0, 10)));
      } catch (err) {
        console.error('Failed to auto-save to localStorage:', err);
      }

      setTimeout(() => {
        setSaveStatus('saved');
      }, 500);
    }, 1500);
  }, []);

  const manualSave = useCallback((title: string, content: string, pageConfig: PageConfig, footnotes?: DocumentFootnote[], endnotes?: DocumentEndnote[]) => {
    setSaveStatus('saving');
    if (autoSaveTimerRef.current) clearTimeout(autoSaveTimerRef.current);

    try {
      const docModel = htmlToJSONDocument(content, title, pageConfig, undefined, undefined, footnotes, endnotes);
      const savedDocs = JSON.parse(localStorage.getItem('saved_documents') || '{}');
      savedDocs[title] = {
        documentModel: docModel,
        content,
        lastModified: new Date().toISOString(),
      };
      localStorage.setItem('saved_documents', JSON.stringify(savedDocs));

      let recents = JSON.parse(localStorage.getItem('recent_documents') || '[]');
      recents = recents.filter((r: any) => r.name !== title);
      recents.unshift({
        name: title,
        date: new Date().toLocaleDateString() + ' ' + new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        path: 'Local Storage'
      });
      localStorage.setItem('recent_documents', JSON.stringify(recents.slice(0, 10)));
    } catch (err) {
      console.error('Failed to save to localStorage:', err);
    }

    setTimeout(() => setSaveStatus('saved'), 500);
  }, []);

  return { saveStatus, triggerAutoSave, manualSave, setSaveStatus };
};

import React, { useEffect } from 'react';

export const useMathLive = (content: string, containerRef: React.RefObject<HTMLElement | null>) => {
  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    // 1. Sync value from math-field to DOM attribute for saving/exporting
    const handleInput = (e: Event) => {
      const target = e.target as HTMLElement & { value?: string };
      if (target.tagName.toLowerCase() === 'math-field') {
         if (target.value !== undefined) {
            target.setAttribute('value', target.value);
         }
      }
    };

    // 2. Navigation: Enter MathField from Editor (Right/Left Arrows)
    const handleKeyDown = (e: KeyboardEvent) => {
        if (!['ArrowRight', 'ArrowLeft'].includes(e.key)) return;

        const selection = window.getSelection();
        if (!selection || !selection.rangeCount) return;
        const range = selection.getRangeAt(0);
        if (!range.collapsed) return;

        let targetWrapper: HTMLElement | null = null;
        const isRight = e.key === 'ArrowRight';

        // Helper to check if a node is our wrapper
        const isWrapper = (node: Node | null): node is HTMLElement => {
            return !!(node && node.nodeType === Node.ELEMENT_NODE && (node as HTMLElement).classList.contains('equation-wrapper'));
        };

        // Logic for Text Node
        if (range.endContainer.nodeType === Node.TEXT_NODE) {
            const textNode = range.endContainer;
            const offset = range.endOffset;
            const len = textNode.textContent?.length || 0;
            const textContent = textNode.textContent || '';

            if (isRight) {
                // Case 1: At exact end of text node: |<wrapper>
                if (offset === len) {
                    if (isWrapper(textNode.nextSibling)) targetWrapper = textNode.nextSibling as HTMLElement;
                }
                // Case 2: Before a trailing ZWS: |\u200B<wrapper>
                // We want to skip the ZWS and enter the wrapper immediately
                else if (offset === len - 1 && textContent[len-1] === '\u200B') {
                     if (isWrapper(textNode.nextSibling)) targetWrapper = textNode.nextSibling as HTMLElement;
                }
            } else {
                // Left Arrow
                // Case 1: At start of text node: <wrapper>|
                if (offset === 0) {
                    if (isWrapper(textNode.previousSibling)) targetWrapper = textNode.previousSibling as HTMLElement;
                }
                // Case 2: After a leading ZWS: <wrapper>\u200B|
                else if (offset === 1 && textContent[0] === '\u200B') {
                    if (isWrapper(textNode.previousSibling)) targetWrapper = textNode.previousSibling as HTMLElement;
                }
            }
        } 
        // Logic for Element Node (cursor is between tags)
        else if (range.endContainer.nodeType === Node.ELEMENT_NODE) {
            const containerNode = range.endContainer;
            const offset = range.endOffset;

            if (isRight) {
                // Node at index `offset` is the one to the right
                const nextNode = containerNode.childNodes[offset];
                if (isWrapper(nextNode)) targetWrapper = nextNode as HTMLElement;
            } else {
                // Node at index `offset - 1` is the one to the left
                if (offset > 0) {
                    const prevNode = containerNode.childNodes[offset - 1];
                    if (isWrapper(prevNode)) targetWrapper = prevNode as HTMLElement;
                }
            }
        }

        if (targetWrapper) {
            const mathField = targetWrapper.querySelector('math-field') as any;
            if (mathField) {
                e.preventDefault();
                mathField.focus();
                // Set internal cursor position
                if (isRight) {
                    mathField.executeCommand('moveToMathFieldStart');
                } else {
                    mathField.executeCommand('moveToMathFieldEnd');
                }
            }
        }
    };

    // 3. Navigation: Exit MathField to Editor (move-out event from MathLive)
    const handleMoveOut = (e: Event) => {
        const target = e.target as HTMLElement;
        if (target.tagName.toLowerCase() !== 'math-field') return;

        const detail = (e as CustomEvent).detail;
        const direction = detail.direction; // 'forward', 'backward', 'up', 'down'
        const wrapper = target.closest('.equation-wrapper');

        if (wrapper && container.contains(wrapper)) {
            const selection = window.getSelection();
            const range = document.createRange();

            if (direction === 'forward' || direction === 'right') {
                // Move to after wrapper
                const nextNode = wrapper.nextSibling;
                // If next is a text node starting with ZWS, jump over it
                if (nextNode && nextNode.nodeType === Node.TEXT_NODE && nextNode.textContent?.startsWith('\u200B')) {
                    range.setStart(nextNode, 1);
                    range.setEnd(nextNode, 1);
                } else {
                    range.setStartAfter(wrapper);
                    range.setEndAfter(wrapper);
                }
            } else if (direction === 'backward' || direction === 'left') {
                // Move to before wrapper
                const prevNode = wrapper.previousSibling;
                // If prev is a text node ending with ZWS, jump before it
                if (prevNode && prevNode.nodeType === Node.TEXT_NODE && prevNode.textContent?.endsWith('\u200B')) {
                    const len = prevNode.textContent!.length;
                    const safeOffset = Math.max(0, len - 1); // Safe guard against 0-length text node
                    range.setStart(prevNode, safeOffset);
                    range.setEnd(prevNode, safeOffset);
                } else {
                    range.setStartBefore(wrapper);
                    range.setEndBefore(wrapper);
                }
            } else {
                return;
            }

            selection?.removeAllRanges();
            selection?.addRange(range);
            container.focus();
        }
    };

    // 4. Interaction: Click on wrapper area (padding/background) focuses the math-field
    const handleClick = (e: MouseEvent) => {
        const target = e.target as HTMLElement;
        const wrapper = target.closest('.equation-wrapper');

        // If clicked on wrapper or handle but not the math-field itself
        if (wrapper && target.tagName.toLowerCase() !== 'math-field') {
             const mathField = wrapper.querySelector('math-field') as HTMLElement;
             if (mathField) {
                 e.preventDefault();
                 e.stopPropagation();
                 mathField.focus();
             }
        }
    };

    container.addEventListener('input', handleInput);
    container.addEventListener('keydown', handleKeyDown);
    container.addEventListener('move-out', handleMoveOut);
    container.addEventListener('click', handleClick);

    return () => {
      container.removeEventListener('input', handleInput);
      container.removeEventListener('keydown', handleKeyDown);
      container.removeEventListener('move-out', handleMoveOut);
      container.removeEventListener('click', handleClick);
    };
  }, [containerRef]); 
};

import { GoogleGenAI, GenerateContentResponse, HarmCategory, HarmBlockThreshold, Modality } from "@google/genai";
import { AIOperation } from '../types';
import { getSystemPrompt, getChatSystemPrompt } from './prompts';

// Safety settings to allow standard business/creative writing without over-blocking
const SAFETY_SETTINGS = [
  { category: HarmCategory.HARM_CATEGORY_HARASSMENT, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
  { category: HarmCategory.HARM_CATEGORY_HATE_SPEECH, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
  { category: HarmCategory.HARM_CATEGORY_SEXUALLY_EXPLICIT, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
  { category: HarmCategory.HARM_CATEGORY_DANGEROUS_CONTENT, threshold: HarmBlockThreshold.BLOCK_ONLY_HIGH },
];

const getClient = () => {
  const localKey = localStorage.getItem('gemini_api_key');
  if (localKey) {
    return new GoogleGenAI({ apiKey: localKey });
  }
  if (process.env.API_KEY) {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }
  return null;
};

const formatGeminiError = (error: any): string => {
  const msg = error.message || error.toString();
  const lowerMsg = msg.toLowerCase();

  if (lowerMsg.includes('429') || lowerMsg.includes('quota') || lowerMsg.includes('exhausted')) {
    return "⚠️ Quota exceeded. The AI usage limit has been reached. Please check your billing or try again later.";
  }
  if (lowerMsg.includes('503') || lowerMsg.includes('overloaded') || lowerMsg.includes('capacity')) {
    return "⚠️ The AI model is currently overloaded. Please try again in a few moments.";
  }
  if (lowerMsg.includes('key') || lowerMsg.includes('auth') || lowerMsg.includes('permission')) {
    return "⚠️ Invalid or missing API Key. Please check your settings in the AI Assistant tab.";
  }
  if (lowerMsg.includes('safety') || lowerMsg.includes('blocked')) {
    return "⚠️ Content blocked by safety filters. Please revise your prompt.";
  }
  return `⚠️ AI Error: ${msg}`;
};

const base64ToUint8Array = (base64: string) => {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
};

export const generateSpeech = async (text: string, voiceName: string = 'Kore'): Promise<Uint8Array | null> => {
  const client = getClient();
  if (!client) {
      console.error("API Key not configured");
      return null;
  }

  // Use stored audio model preference
  const storedModel = localStorage.getItem('gemini_model_audio');
  const effectiveModel = storedModel || "gemini-2.5-flash-preview-tts";

  try {
    // Truncate text if too long to prevent errors (approx limit check for TTS model)
    const safeText = text.slice(0, 4000); 

    const response = await client.models.generateContent({
      model: effectiveModel,
      contents: [{ parts: [{ text: safeText }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName },
            },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
        return base64ToUint8Array(base64Audio);
    }
    return null;

  } catch (error) {
    console.error("[Gemini Service] Speech Gen Error:", error);
    return null;
  }
};

export const generateAIContent = async (
  operation: AIOperation,
  text: string,
  userPrompt?: string,
  model: string = "gemini-3-pro-preview"
): Promise<string> => {
  // Use stored text model preference (with fallback to legacy key or default param)
  const storedModel = localStorage.getItem('gemini_model_text') || localStorage.getItem('gemini_model');
  const effectiveModel = storedModel || model;

  console.log(`[Gemini Service] generateAIContent. Op: ${operation}, Model: ${effectiveModel}`);
  const client = getClient();
  if (!client) {
    return JSON.stringify({ error: "API Key not configured. Please use the Settings in the AI Assistant tab." });
  }

  const systemPrompt = getSystemPrompt(operation, userPrompt);

  try {
    const response = await client.models.generateContent({
      model: effectiveModel,
      contents: [
        { role: "user", parts: [{ text: `SYSTEM INSTRUCTIONS:\n${systemPrompt}\n\nINPUT DATA:\n${text}` }] }
      ],
      config: {
        responseMimeType: "application/json", 
        safetySettings: SAFETY_SETTINGS,
        temperature: 0.7, // Balanced creativity
        topK: 40,
        topP: 0.95,
      }
    });

    if (!response.text) {
        throw new Error("Empty response received from AI.");
    }

    return response.text;
  } catch (error: any) {
    console.error("[Gemini Service] Error:", error);
    return JSON.stringify({ error: formatGeminiError(error) });
  }
};

export const streamAIContent = async function* (
  operation: AIOperation,
  text: string,
  userPrompt?: string,
  model: string = "gemini-3-pro-preview"
): AsyncGenerator<string, void, unknown> {
  const storedModel = localStorage.getItem('gemini_model_text') || localStorage.getItem('gemini_model');
  const effectiveModel = storedModel || model;

  const client = getClient();
  if (!client) throw new Error("API Key not configured.");

  const systemPrompt = getSystemPrompt(operation, userPrompt);

  try {
    const responseStream = await client.models.generateContentStream({
      model: effectiveModel,
      contents: [
        { role: "user", parts: [{ text: `SYSTEM INSTRUCTIONS:\n${systemPrompt}\n\nINPUT DATA:\n${text}` }] }
      ],
      config: {
        safetySettings: SAFETY_SETTINGS
      }
    });

    for await (const chunk of responseStream) {
      const c = chunk as GenerateContentResponse;
      if (c.text) {
        yield c.text;
      }
    }
  } catch (error) {
    console.error("[Gemini Service] Stream Error:", error);
    throw new Error(formatGeminiError(error), { cause: error });
  }
};

export const chatWithDocumentStream = async function* (
  history: { role: 'user' | 'model', text: string }[],
  lastMessage: string,
  documentContent: string,
  model: string = "gemini-3-pro-preview"
): AsyncGenerator<string, void, unknown> {
  const storedModel = localStorage.getItem('gemini_model_text') || localStorage.getItem('gemini_model');
  const effectiveModel = storedModel || model;

  const client = getClient();
  if (!client) throw new Error("API Key not configured.");

  const systemInstruction = getChatSystemPrompt(documentContent);

  const historyContent = history.map(msg => ({
    role: msg.role,
    parts: [{ text: msg.text }]
  }));

  try {
    const chat = client.chats.create({
      model: effectiveModel,
      config: { 
        systemInstruction,
        safetySettings: SAFETY_SETTINGS
      },
      history: historyContent
    });

    const responseStream = await chat.sendMessageStream({ message: lastMessage });

    for await (const chunk of responseStream) {
        const c = chunk as GenerateContentResponse;
        if (c.text) {
            yield c.text;
        }
    }
  } catch (error) {
    console.error("[Gemini Service] Chat Error:", error);
    throw new Error(formatGeminiError(error), { cause: error });
  }
};

export const generateAIImage = async (prompt: string): Promise<string | null> => {
  const client = getClient();
  if (!client) throw new Error("API Key not configured.");

  // Use stored image model preference
  const storedModel = localStorage.getItem('gemini_model_image');
  const effectiveModel = storedModel || 'gemini-2.5-flash-image';

  try {
    // Branch logic: Imagen vs Gemini models
    if (effectiveModel.toLowerCase().includes('imagen')) {
         const response = await client.models.generateImages({
            model: effectiveModel,
            prompt: prompt,
            config: {
              numberOfImages: 1,
              outputMimeType: 'image/jpeg',
              aspectRatio: '1:1', // Default to square
            },
         });

         const base64EncodeString = response.generatedImages?.[0]?.image?.imageBytes;
         if (base64EncodeString) {
             return `data:image/jpeg;base64,${base64EncodeString}`;
         }
    } else {
        // Standard Gemini Image Generation
        const response = await client.models.generateContent({
          model: effectiveModel,
          contents: {
            parts: [{ text: prompt }],
          },
          config: {
            safetySettings: SAFETY_SETTINGS
          }
        });

        if (response.candidates && response.candidates.length > 0) {
          for (const part of response.candidates[0].content.parts) {
            if (part.inlineData && part.inlineData.mimeType.startsWith('image/')) {
              return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
            }
          }
        }
    }
    return null;
  } catch (error: any) {
    console.error("[Gemini Service] Image Gen Error:", error);
    throw new Error(formatGeminiError(error), { cause: error });
  }
};

import { GoogleGenAI, LiveServerMessage, Modality, Blob } from '@google/genai';

export class LiveService {
  private client: GoogleGenAI | null = null;
  private session: any = null;
  private audioContext: AudioContext | null = null;
  private processor: ScriptProcessorNode | null = null;
  private source: MediaStreamAudioSourceNode | null = null;
  private stream: MediaStream | null = null;
  private isConnected: boolean = false;

  constructor() {
    // Client initialized lazily in connect()
  }

  private getClient(): GoogleGenAI {
    if (!this.client) {
      // Prioritize localStorage key if user set it in settings, else env var
      const localKey = localStorage.getItem('gemini_api_key');
      const apiKey = localKey || process.env.API_KEY;

      if (!apiKey) {
        throw new Error("API Key is missing. Please check your environment configuration or settings.");
      }
      this.client = new GoogleGenAI({ apiKey });
    }
    return this.client;
  }

  async connect(
    onTranscription: (text: string) => void,
    onError: (error: Error) => void,
    onClose: () => void
  ) {
    if (this.isConnected) return;

    try {
      const client = this.getClient();

      // 1. Get Microphone Stream FIRST
      // This ensures we have mic permission and hardware before spinning up AudioContext/Gemini Session
      // Using relaxed constraints (audio: true) to avoid OverconstrainedError on devices that don't natively support 16kHz
      this.stream = await navigator.mediaDevices.getUserMedia({
        audio: true, 
      });

      // 2. Initialize Audio Context with target sample rate
      // Modern browsers will resample the stream to match this context automatically
      this.audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({
        sampleRate: 16000,
      });

      // 3. Initialize Gemini Session
      this.session = await client.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO], // Audio response is required by API, but we will ignore it
          inputAudioTranscription: {}, // Enable transcription of user input
          systemInstruction: "You are a precise dictation assistant. Your only task is to transcribe the user's speech exactly. Do not reply, do not chat, and do not generate audio output.",
        },
        callbacks: {
          onopen: () => {
            console.log("Dictation Session Opened");
            this.isConnected = true;
            // Start streaming only after session is ready
            this.startAudioStreaming();
          },
          onmessage: (message: LiveServerMessage) => {
            // We only care about the input transcription (what the user said)
            const transcript = message.serverContent?.inputTranscription?.text;
            if (transcript) {
              onTranscription(transcript);
            }
          },
          onclose: () => {
            console.log("Dictation Session Closed");
            this.cleanup();
            onClose();
          },
          onerror: (err) => {
            console.error("Dictation Session Error:", err);
            this.cleanup();
            onError(new Error("Connection error"));
          }
        }
      });

    } catch (error: any) {
      console.error("Failed to start dictation:", error);
      this.cleanup();

      // Improve error message for common issues
      if (error.name === 'NotAllowedError' || error.name === 'PermissionDeniedError') {
         onError(new Error("Microphone permission denied. Please allow microphone access in your browser settings."));
      } else if (error.name === 'NotFoundError' || error.name === 'DevicesNotFoundError') {
         onError(new Error("No microphone found. Please check your system audio settings and permissions."));
      } else if (error.name === 'OverconstrainedError') {
         onError(new Error("Microphone hardware constraints not met."));
      } else if (error.name === 'NotSupportedError') {
         onError(new Error("Audio sample rate not supported by this browser."));
      } else {
         onError(error);
      }
    }
  }

  private startAudioStreaming() {
    if (!this.audioContext || !this.stream || !this.session) return;

    try {
        this.source = this.audioContext.createMediaStreamSource(this.stream);
        this.processor = this.audioContext.createScriptProcessor(4096, 1, 1);

        this.processor.onaudioprocess = (e) => {
          if (!this.isConnected || !this.session) return;

          const inputData = e.inputBuffer.getChannelData(0);
          const pcmBlob = this.createBlob(inputData);

          // Ensure session is ready before sending
          this.session.sendRealtimeInput({ media: pcmBlob });
        };

        this.source.connect(this.processor);
        this.processor.connect(this.audioContext.destination);
    } catch (e) {
        console.error("Error starting audio stream:", e);
    }
  }

  disconnect() {
    this.isConnected = false;
    if (this.session) {
      try {
        this.session.close();
      } catch (e) {
        console.warn("Error closing session:", e);
      }
    }
    this.cleanup();
  }

  private cleanup() {
    this.isConnected = false;
    this.session = null;

    if (this.processor) {
      try {
        this.processor.disconnect();
        this.processor.onaudioprocess = null;
      } catch (_e) {
        // ignore
      }
      this.processor = null;
    }

    if (this.source) {
      try {
        this.source.disconnect();
      } catch (_e) {
        // ignore
      }
      this.source = null;
    }

    if (this.stream) {
      try {
        this.stream.getTracks().forEach(track => track.stop());
      } catch (_e) {
        // ignore
      }
      this.stream = null;
    }

    if (this.audioContext) {
      try {
        this.audioContext.close();
      } catch (_e) {
        // ignore
      }
      this.audioContext = null;
    }
  }

  private createBlob(data: Float32Array): Blob {
    const l = data.length;
    const int16 = new Int16Array(l);
    for (let i = 0; i < l; i++) {
      const s = Math.max(-1, Math.min(1, data[i]));
      int16[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;
    }
    return {
      data: this.base64EncodeInt16(int16),
      mimeType: 'audio/pcm;rate=16000',
    };
  }

  private base64EncodeInt16(int16: Int16Array): string {
    let binary = '';
    const bytes = new Uint8Array(int16.buffer);
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) {
      binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
  }
}

