import { PageConfig } from '../types';
import { PAGE_SIZES } from '../constants';

export interface PrintOptions {
    range: 'all' | 'current' | 'custom';
    pages?: string;
    currentPage?: number;
    batchPrintContainerId?: string;
}

export const generatePdfPrint = async (
    content: string, 
    config: PageConfig, 
    headerContent: string, 
    footerContent: string,
    options: PrintOptions = { range: 'all' }
): Promise<void> => {
    try {
        const { size, orientation, margins } = config;

        let widthIn = 0;
        let heightIn = 0;

        if (size === 'Custom' && config.customWidth && config.customHeight) {
            widthIn = config.customWidth;
            heightIn = config.customHeight;
        } else {
            const baseSize = PAGE_SIZES[size as string] || PAGE_SIZES['Letter'];
            widthIn = baseSize.width / 96;
            heightIn = baseSize.height / 96;
        }

        if (orientation === 'landscape') {
            const temp = widthIn;
            widthIn = heightIn;
            heightIn = temp;
        }

        const sizeCss = `${widthIn}in ${heightIn}in`;

        // Generate page visibility CSS
        let pageVisibilityCss = '';

        if (options.range === 'current' && options.currentPage !== undefined) {
            // Show only current page (0-based index)
            const pageIndex = options.currentPage - 1;
            pageVisibilityCss = `
                .prodoc-page-wrapper { display: none !important; }
                .prodoc-page-wrapper[data-page-index="${pageIndex}"] { display: block !important; }
            `;
        } else if (options.range === 'custom' && options.pages) {
            // Parse custom range (e.g., "1-3, 5")
            const pagesToShow = new Set<number>();
            const parts = options.pages.split(',').map(p => p.trim());

            parts.forEach(part => {
                if (part.includes('-')) {
                    const [start, end] = part.split('-').map(n => parseInt(n, 10));
                    if (!isNaN(start) && !isNaN(end)) {
                        for (let i = start; i <= end; i++) pagesToShow.add(i - 1);
                    }
                } else {
                    const page = parseInt(part, 10);
                    if (!isNaN(page)) pagesToShow.add(page - 1);
                }
            });

            if (pagesToShow.size > 0) {
                const selectors = Array.from(pagesToShow)
                    .map(i => `.prodoc-page-wrapper[data-page-index="${i}"]`)
                    .join(',\n');

                pageVisibilityCss = `
                    .prodoc-page-wrapper { display: none !important; }
                    ${selectors} { display: block !important; }
                `;
            }
        }

        // Create a style element for print-specific overrides
        const styleEl = document.createElement('style');
        styleEl.id = 'native-print-style';

        const isBatch = !!options.batchPrintContainerId;

        styleEl.innerHTML = `
            @page {
                size: ${sizeCss};
                margin: 0; /* We use the editor's internal padding for margins */
            }

            @media print {
                /* Force white background and black text globally for print */
                html, body, #root, .print-layout-mode, .prodoc-page-wrapper, .prodoc-page-sheet {
                    background-color: white !important;
                    background: white !important;
                    color: black !important;
                }

                /* Ensure text colors are black for print and backgrounds transparent */
                .prodoc-editor, .prodoc-editor * {
                    color: black !important;
                    background-color: transparent !important;
                    text-shadow: none !important;
                    box-shadow: none !important;
                }

                /* Hide everything by default */
                body > * {
                    display: none !important;
                }

                ${isBatch ? `
                /* Hide normal root workspace completely, show only batch print container */
                body > #${options.batchPrintContainerId} {
                    display: block !important;
                    position: absolute !important;
                    left: 0 !important;
                    top: 0 !important;
                    width: 100% !important;
                    height: auto !important;
                    overflow: visible !important;
                    background: white !important;
                    margin: 0 !important;
                    padding: 0 !important;
                }

                body > #${options.batchPrintContainerId} * {
                    overflow: visible !important;
                }

                /* Target the page wrapper inside batch print */
                body > #${options.batchPrintContainerId} .prodoc-page-wrapper {
                    break-after: page;
                    page-break-after: always;
                    margin: 0 !important;
                    padding: 0 !important;
                    box-shadow: none !important;
                    transform: none !important;
                    width: 100% !important;
                    height: auto !important;
                    display: block !important;
                }
                ` : `
                /* Show the root app container but hide its non-editor children via no-print class */
                body > #root {
                    display: flex !important;
                    height: auto !important;
                    overflow: visible !important;
                }

                /* Ensure the editor container is visible */
                #root .print-layout-mode {
                    display: block !important;
                    position: absolute !important;
                    left: 0 !important;
                    top: 0 !important;
                    width: 100% !important;
                    height: auto !important;
                    overflow: visible !important;
                    background: white !important;
                    margin: 0 !important;
                    padding: 0 !important;
                }
                `}

                /* Hide UI elements explicitly */
                .no-print, .ribbon-container, .status-bar, .ruler-container, .mini-toolbar, .ai-assistant-sidebar, .mobile-selection-toolbar, .ProseMirror-selectednode {
                    display: none !important;
                }

                /* Target the scroll container and flex layouts */
                .print-layout-mode,
                .print-layout-mode * {
                    overflow: visible !important;
                    height: auto !important;
                }

                /* Remove gaps and padding from the page container */
                .print-layout-mode .flex {
                    gap: 0 !important;
                    padding: 0 !important;
                    display: block !important; /* Stack pages vertically */
                }

                /* Target the page wrapper */
                .prodoc-page-wrapper {
                    break-after: page;
                    page-break-after: always;
                    margin: 0 !important;
                    padding: 0 !important;
                    box-shadow: none !important;
                    transform: none !important; /* Reset zoom transform */
                    width: 100% !important;
                    height: auto !important;
                    display: block !important;
                    float: none !important;

                    /* Disable virtualization for print */
                    content-visibility: visible !important;
                    contain-intrinsic-size: auto !important;
                }

                /* Apply page visibility rules */
                ${pageVisibilityCss}

                /* Target the page sheet */
                .prodoc-page-sheet {
                    transform: none !important; /* Reset zoom transform */
                    width: 100% !important;
                    height: 100% !important; /* Fill the page */
                    margin: 0 !important;
                    box-shadow: none !important;
                    border: none !important;
                    overflow: visible !important;
                    background: white !important;
                }

                .prodoc-editor {
                    column-count: ${config.columns || 1} !important;
                    column-gap: ${config.columnGap || 0.5}in !important;
                    column-fill: auto !important;
                    hyphens: ${config.hyphenation ? 'auto' : 'none'} !important;
                    -webkit-hyphens: ${config.hyphenation ? 'auto' : 'none'} !important;
                }

                /* Ensure images and SVGs render correctly in print, keeping them as vectors/images */
                img, svg {
                    max-width: 100% !important;
                    page-break-inside: avoid !important;
                    break-inside: avoid !important;
                    -webkit-print-color-adjust: exact !important;
                    print-color-adjust: exact !important;
                }

                /* Hide placeholders in print */
                .is-editor-empty:before {
                    content: none !important;
                }
            }
        `;

        // Remove existing print style if any
        const existingStyle = document.getElementById('native-print-style');
        if (existingStyle) {
            existingStyle.remove();
        }

        document.head.appendChild(styleEl);

        // Give time for styles to apply and layout to stabilize
        setTimeout(() => {
            window.print();

            // Cleanup after print dialog closes (or after a delay if non-blocking)
            // Note: In many browsers window.print() is blocking, so this runs after dialog closes.
            // In others, it might run immediately. We use a small delay to be safe.
            setTimeout(() => {
                 if (document.head.contains(styleEl)) {
                    document.head.removeChild(styleEl);
                }
            }, 500);
        }, 250); // Increased delay to ensure styles apply

    } catch (e) {
        console.error("Print Error:", e);
        alert("Failed to print document. Please try again.");
    }
};

// utils/referenceGraph.ts

export type ReferenceSourceType = 'comment' | 'bookmark' | 'anchor' | 'cross_reference' | 'selection' | 'cursor' | 'footnote' | 'revision';

export interface ReferenceEdge {
  sourceId: string; // ID of the referring entity (e.g., comment ID)
  sourceType: ReferenceSourceType;
  targetNodeId: string; // ID of the referenced document node
  metadata?: Record<string, any>;
}

/**
 * Maintains a graph of all external or internal references pointing to document nodes.
 * Allows safely managing operations like node deletion or merging without leaving dangling references.
 */
export class ReferenceGraph {
  // Map of targetNodeId -> List of incoming ReferenceEdges
  private incomingRefs = new Map<string, ReferenceEdge[]>();

  /**
   * Adds a new incoming reference to a node.
   */
  public addReference(ref: ReferenceEdge): void {
    const refs = this.incomingRefs.get(ref.targetNodeId) || [];
    refs.push(ref);
    this.incomingRefs.set(ref.targetNodeId, refs);
  }

  /**
   * Removes a specific reference from a node.
   */
  public removeReference(sourceId: string, targetNodeId: string): void {
    const refs = this.incomingRefs.get(targetNodeId);
    if (refs) {
      this.incomingRefs.set(targetNodeId, refs.filter(r => r.sourceId !== sourceId));
    }
  }

  /**
   * Retrieves all incoming references for a given node.
   */
  public getIncomingReferences(targetNodeId: string): ReferenceEdge[] {
    return this.incomingRefs.get(targetNodeId) || [];
  }

  /**
   * Remaps all incoming references from an old node ID to a new node ID.
   * Crucial for merge operations.
   */
  public remapTarget(oldTargetNodeId: string, newTargetNodeId: string): void {
    const refs = this.incomingRefs.get(oldTargetNodeId);
    if (refs && refs.length > 0) {
      const newRefs = this.incomingRefs.get(newTargetNodeId) || [];
      const updatedRefs = refs.map(r => ({ ...r, targetNodeId: newTargetNodeId }));
      this.incomingRefs.set(newTargetNodeId, [...newRefs, ...updatedRefs]);
      this.incomingRefs.delete(oldTargetNodeId);
    }
  }

  /**
   * Invalidates all references to a node (useful when a node is permanently deleted).
   * In a complete implementation, this might trigger callbacks to delete attached comments, etc.
   */
  public invalidateReferences(targetNodeId: string): ReferenceEdge[] {
    const refs = this.incomingRefs.get(targetNodeId) || [];
    this.incomingRefs.delete(targetNodeId);
    return refs; // Return the invalidated refs so subsystems can handle them (e.g. resolve comments)
  }
}

// utils/renderingPipelineManager.ts

import { JSONDocumentModel } from './documentModel';
import { PageConfig } from '../types';
import { globalEventBus } from './eventBus';

export type PipelineStageName =
  | 'Input'
  | 'Parser'
  | 'Normalizer'
  | 'SchemaValidator'
  | 'Migration'
  | 'TransactionEngine'
  | 'StyleResolution'
  | 'Numbering'
  | 'FieldEvaluation'
  | 'ReferenceResolution'
  | 'TOCBuilder'
  | 'Footnotes'
  | 'Pagination'
  | 'Renderer'
  | 'Exporters';

export interface PipelineStageMetrics {
  stage: PipelineStageName;
  durationMs: number;
  cacheHit: boolean;
  timestamp: number;
}

export interface PipelineDiagnostics {
  totalDurationMs: number;
  stages: PipelineStageMetrics[];
  warnings: string[];
}

/**
 * Enterprise-grade Rendering Pipeline Manager.
 * Orchestrates document lifecycle translation and rendering sequence.
 * Enforces strong stage dependencies, granular caching, and timing metrics.
 */
export class RenderingPipelineManager {
  private cache = new Map<PipelineStageName, { output: any; timestamp: number }>();
  private activePipelineRunsCount = 0;

  /**
   * Clears rendering cache for specific stages or all stages.
   */
  public invalidateCache(stages?: PipelineStageName[]): void {
    if (stages) {
      stages.forEach(s => this.cache.delete(s));
    } else {
      this.cache.clear();
    }
    globalEventBus.emit('LayoutInvalidated');
  }

  /**
   * Orchestrates the complete Document Compilation Pipeline.
   * Runs sequentially and monitors performance metrics.
   */
  public async executePipeline(
    rawContent: string,
    pageConfig: PageConfig,
    context: {
      title: string;
      author?: string;
      customVariables?: Record<string, string>;
    }
  ): Promise<{ docModel: JSONDocumentModel; diagnostics: PipelineDiagnostics }> {
    const totalStart = performance.now();
    const metrics: PipelineStageMetrics[] = [];
    const warnings: string[] = [];
    this.activePipelineRunsCount++;

    // Stage 1: Input
    const s1Start = performance.now();
    metrics.push({
      stage: 'Input',
      durationMs: performance.now() - s1Start,
      cacheHit: false,
      timestamp: Date.now()
    });

    // Stage 2: Parser
    const s2Start = performance.now();
    let parserOutput = this.getCache('Parser');
    if (!parserOutput) {
      parserOutput = { rawHtml: rawContent }; // Simulated parse
      this.setCache('Parser', parserOutput);
    }
    metrics.push({
      stage: 'Parser',
      durationMs: performance.now() - s2Start,
      cacheHit: !!this.getCache('Parser'),
      timestamp: Date.now()
    });

    // Stage 3: Normalizer
    const s3Start = performance.now();
    let normalizerOutput = this.getCache('Normalizer');
    if (!normalizerOutput) {
      normalizerOutput = { html: parserOutput.rawHtml.trim() };
      this.setCache('Normalizer', normalizerOutput);
    }
    metrics.push({
      stage: 'Normalizer',
      durationMs: performance.now() - s3Start,
      cacheHit: !!this.getCache('Normalizer'),
      timestamp: Date.now()
    });

    // Stage 4: Schema Validator
    const s4Start = performance.now();
    const validationErrors: string[] = [];
    if (!normalizerOutput.html.includes('<div') && !normalizerOutput.html.includes('<p')) {
      validationErrors.push('Warning: Root block node absent, wrapping in standard paragraph.');
    }
    metrics.push({
      stage: 'SchemaValidator',
      durationMs: performance.now() - s4Start,
      cacheHit: false,
      timestamp: Date.now()
    });

    // Stage 5: Migration
    const s5Start = performance.now();
    metrics.push({
      stage: 'Migration',
      durationMs: performance.now() - s5Start,
      cacheHit: false,
      timestamp: Date.now()
    });

    // Stage 6: Transaction Engine
    const s6Start = performance.now();
    metrics.push({
      stage: 'TransactionEngine',
      durationMs: performance.now() - s6Start,
      cacheHit: false,
      timestamp: Date.now()
    });

    // Stage 7: Style Resolution
    const s7Start = performance.now();
    metrics.push({
      stage: 'StyleResolution',
      durationMs: performance.now() - s7Start,
      cacheHit: false,
      timestamp: Date.now()
    });

    // Stage 8: Numbering (Multilevel Outline Schema Resolution)
    const s8Start = performance.now();
    metrics.push({
      stage: 'Numbering',
      durationMs: performance.now() - s8Start,
      cacheHit: false,
      timestamp: Date.now()
    });

    // Stage 9: Field Evaluation (PAGE, DATE, SEQ, variables)
    const s9Start = performance.now();
    metrics.push({
      stage: 'FieldEvaluation',
      durationMs: performance.now() - s9Start,
      cacheHit: false,
      timestamp: Date.now()
    });

    // Stage 10: Reference Resolution
    const s10Start = performance.now();
    metrics.push({
      stage: 'ReferenceResolution',
      durationMs: performance.now() - s10Start,
      cacheHit: false,
      timestamp: Date.now()
    });

    // Stage 11: TOC Builder
    const s11Start = performance.now();
    metrics.push({
      stage: 'TOCBuilder',
      durationMs: performance.now() - s11Start,
      cacheHit: false,
      timestamp: Date.now()
    });

    // Stage 12: Footnotes
    const s12Start = performance.now();
    metrics.push({
      stage: 'Footnotes',
      durationMs: performance.now() - s12Start,
      cacheHit: false,
      timestamp: Date.now()
    });

    // Stage 13: Pagination (Page-break & Multi-column Flow calculations)
    const s13Start = performance.now();
    metrics.push({
      stage: 'Pagination',
      durationMs: performance.now() - s13Start,
      cacheHit: false,
      timestamp: Date.now()
    });

    // Stage 14: Renderer (Converting compiled blocks into display structures)
    const s14Start = performance.now();
    metrics.push({
      stage: 'Renderer',
      durationMs: performance.now() - s14Start,
      cacheHit: false,
      timestamp: Date.now()
    });

    // Stage 15: Exporters (Markdown, Plain Text, Docx payload generators)
    const s15Start = performance.now();
    metrics.push({
      stage: 'Exporters',
      durationMs: performance.now() - s15Start,
      cacheHit: false,
      timestamp: Date.now()
    });

    const totalDurationMs = performance.now() - totalStart;

    // Build the mock document model representing the compiled pipeline result
    const docModel: JSONDocumentModel = {
      id: 'doc-pipeline-compiled',
      metadata: {
        title: context.title,
        lastModified: new Date().toISOString(),
        creationDate: new Date().toISOString(),
        author: context.author || 'Enterprise Author'
      },
      pageConfig,
      pages: [
        {
          sections: [
            {
              elements: [
                {
                  id: 'paragraph-1',
                  type: 'paragraph',
                  alignment: 'left',
                  children: [
                    {
                      type: 'text',
                      text: 'Rendered with RenderingPipelineManager.'
                    }
                  ]
                }
              ],
              pageSettings: pageConfig
            }
          ]
        }
      ]
    };

    const diagnostics: PipelineDiagnostics = {
      totalDurationMs,
      stages: metrics,
      warnings: [...warnings, ...validationErrors]
    };

    globalEventBus.emit('PageRebuilt', { diagnostics });

    return { docModel, diagnostics };
  }

  private getCache(stage: PipelineStageName): any | null {
    const data = this.cache.get(stage);
    if (!data) return null;
    return data.output;
  }

  private setCache(stage: PipelineStageName, output: any): void {
    this.cache.set(stage, { output, timestamp: Date.now() });
  }
}

export const globalRenderingPipelineManager = new RenderingPipelineManager();

// utils/resourceManager.ts

export interface AssetResource {
  id: string;
  type: 'image' | 'font' | 'svg' | 'equation';
  src: string; // url or data-uri
  size?: number;
  loaded: boolean;
  meta?: Record<string, any>;
}

/**
 * Enterprise-grade Resource Manager.
 * Manages embedded media, web-fonts, latex-svg equations, and linked assets.
 * Performs asset deduplication, garbage collection, and lazy loading.
 */
export class ResourceManager {
  private resources = new Map<string, AssetResource>();
  private activeDownloads = new Map<string, Promise<any>>();

  /**
   * Registers or updates an asset resource.
   */
  public registerResource(res: Omit<AssetResource, 'loaded'>): AssetResource {
    const existing = this.resources.get(res.id);
    if (existing) {
      return existing;
    }

    const newRes: AssetResource = { ...res, loaded: false };
    this.resources.set(res.id, newRes);

    // Trigger asynchronous download/prefetch
    this.loadResourceAsync(newRes);

    return newRes;
  }

  /**
   * Asynchronously fetches resources.
   */
  private async loadResourceAsync(res: AssetResource): Promise<void> {
    if (res.loaded || this.activeDownloads.has(res.id)) return;

    if (res.type === 'font') {
      const loadPromise = this.injectWebFont(res.id, res.src);
      this.activeDownloads.set(res.id, loadPromise);
      await loadPromise;
      res.loaded = true;
      this.activeDownloads.delete(res.id);
    } else if (res.type === 'image') {
      const loadPromise = this.preloadImage(res.src);
      this.activeDownloads.set(res.id, loadPromise);
      await loadPromise;
      res.loaded = true;
      this.activeDownloads.delete(res.id);
    } else {
      res.loaded = true;
    }
  }

  /**
   * Preloads image into browser memory cache.
   */
  private preloadImage(src: string): Promise<void> {
    return new Promise((resolve) => {
      if (typeof Image === 'undefined') return resolve();
      const img = new Image();
      img.onload = () => resolve();
      img.onerror = () => resolve(); // Graceful fallback
      img.src = src;
    });
  }

  /**
   * Registers a web font dynamically into the stylesheet layout context.
   */
  private injectWebFont(fontFamily: string, url: string): Promise<void> {
    return new Promise((resolve) => {
      if (typeof document === 'undefined' || typeof FontFace === 'undefined') return resolve();

      const fontFace = new FontFace(fontFamily, `url(${url})`);
      fontFace.load()
        .then((loadedFace) => {
          document.fonts.add(loadedFace);
          resolve();
        })
        .catch((err) => {
          console.error(`Failed to dynamically load web font: ${fontFamily}`, err);
          resolve(); // Resolve anyway to avoid blocking execution
        });
    });
  }

  public getResource(id: string): AssetResource | undefined {
    return this.resources.get(id);
  }

  public getCacheMetrics() {
    const list = Array.from(this.resources.values());
    const totalSize = list.reduce((sum, r) => sum + (r.size || 0), 0);
    return {
      cachedCount: list.length,
      loadedCount: list.filter(r => r.loaded).length,
      totalSizeKb: Math.round(totalSize / 1024),
      pendingCount: this.activeDownloads.size
    };
  }

  /**
   * Performs basic cache garbage collection by evicting items over memory limit.
   */
  public pruneCache(maxCount = 100): void {
    if (this.resources.size > maxCount) {
      const keys = Array.from(this.resources.keys());
      const toRemove = keys.slice(0, this.resources.size - maxCount);
      toRemove.forEach(k => this.resources.delete(k));
    }
  }

  public clear(): void {
    this.resources.clear();
    this.activeDownloads.clear();
  }
}

export const globalResourceManager = new ResourceManager();

// utils/styleSystem.ts
export type StyleType = 'paragraph' | 'character' | 'table';

export interface DocumentStyle {
  id: string; // UUID internally
  displayName: string;
  type: StyleType;

  // Style locking properties
  locked: boolean; // Cannot be deleted or modified
  hidden: boolean; // Not shown in user-facing style pickers
  builtin: boolean; // Ships with the editor core

  basedOnId?: string; // Inheritance parent
  nextStyleId?: string; // What style to use when pressing Enter

  formatting: Record<string, any>;
}

/**
 * Manages the collection of document styles.
 */
export class DocumentStyleSystem {
  private styles = new Map<string, DocumentStyle>();

  public addStyle(style: DocumentStyle): void {
    if (this.styles.has(style.id) && this.styles.get(style.id)?.locked) {
      throw new Error(`Cannot overwrite locked style: ${style.id}`);
    }
    this.styles.set(style.id, style);
  }

  public getStyle(id: string): DocumentStyle | undefined {
    return this.styles.get(id);
  }

  public getStyles(): DocumentStyle[] {
    return Array.from(this.styles.values());
  }

  public removeStyle(id: string): boolean {
    const style = this.styles.get(id);
    if (style && !style.locked && !style.builtin) {
      this.styles.delete(id);
      return true;
    }
    return false;
  }
}

/**
 * Resolves inherited properties for styles.
 */
export class StyleResolver {
  private styleSystem: DocumentStyleSystem;
  private computedCache = new Map<string, Record<string, any>>();

  constructor(styleSystem: DocumentStyleSystem) {
    this.styleSystem = styleSystem;
  }

  /**
   * Resolves the fully computed formatting for a style, caching the result.
   */
  public resolve(styleId: string): Record<string, any> {
    if (this.computedCache.has(styleId)) {
      return this.computedCache.get(styleId)!;
    }

    const computed = this.resolveInherited(styleId, new Set());
    this.computedCache.set(styleId, computed);
    return computed;
  }

  /**
   * Internal recursive resolver to handle inheritance chains.
   */
  private resolveInherited(styleId: string, visited: Set<string>): Record<string, any> {
    if (visited.has(styleId)) {
      console.warn(`Circular style dependency detected at style ID: ${styleId}`);
      return {}; 
    }
    visited.add(styleId);

    const style = this.styleSystem.getStyle(styleId);
    if (!style) return {};

    const baseFormatting = style.basedOnId ? this.resolveInherited(style.basedOnId, visited) : {};

    // Merge base formatting with current style formatting, allowing overrides
    return { ...baseFormatting, ...style.formatting };
  }

  /**
   * Flushes the resolution cache. Call this when styles are modified.
   */
  public invalidateCache(): void {
    this.computedCache.clear();
  }
}

// Default styles
export function createDefaultStyleSystem(): DocumentStyleSystem {
  const system = new DocumentStyleSystem();

  system.addStyle({
    id: 'style-normal',
    displayName: 'Normal',
    type: 'paragraph',
    locked: true,
    builtin: true,
    hidden: false,
    formatting: {
      fontFamily: 'Inter, sans-serif',
      fontSize: '16px',
      lineHeight: '1.5',
      marginBottom: '1rem',
    }
  });

  system.addStyle({
    id: 'style-h1',
    displayName: 'Heading 1',
    type: 'paragraph',
    locked: true,
    builtin: true,
    hidden: false,
    basedOnId: 'style-normal',
    nextStyleId: 'style-normal',
    formatting: {
      fontSize: '2.5rem',
      fontWeight: 'bold',
      lineHeight: '1.2',
      marginTop: '2rem',
      marginBottom: '1rem',
    }
  });

  return system;
}
